// =============================================================================
// runtime.ts — рантайм-библиотека Idyllium
// =============================================================================
//
// Этот файл предоставляет объект $rt, на который ссылается весь
// сгенерированный JS-код.  Запускается в браузере.
//
// Содержит:
//   • IdylRuntimeError — класс ошибок времени выполнения
//   • IdylArray        — обёртка массива с проверкой границ
//   • Встроенные функции: div, mod, to_int, to_float, to_string,
//                          max, min, sum, avg
//   • Строковые утилиты: strContains, strFind, strCount, …
//   • Библиотеки: console, math, random, time, file
//   • createRuntime()  — фабрика, порождающая $rt
// =============================================================================


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 1 — RUNTIME ERROR
// ─────────────────────────────────────────────────────────────────────────────

export class IdylRuntimeError extends Error {
    readonly idylFile: string;
    readonly idylLine: number;

    constructor(file: string, line: number, message: string) {
        const formatted = `${file}:${line}: runtime error: ${message}`;
        super(formatted);
        this.name = 'IdylRuntimeError';
        this.idylFile = file;
        this.idylLine = line;
    }
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 2 — IDYL ARRAY
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Обёртка массива с проверкой границ при каждом доступе.
 *
 * Покрывает как array<T, N> (fixed = true), так и dyn_array<T> (fixed = false).
 *
 * Все методы, модифицирующие размер, запрещены для фиксированных массивов.
 */
export class IdylArray<T> {

    private data: T[];
    private readonly fixed: boolean;

    private constructor(data: T[], fixed: boolean) {
        this.data = data;
        this.fixed = fixed;
    }

    // ── Фабричные методы ────────────────────────────────────────────

    /** Создаёт массив из JS-массива литералов. */
    static from<T>(elements: T[], expectedSize: number, fixed: boolean): IdylArray<T> {
        const arr = new IdylArray<T>([...elements], fixed);
        // Для фиксированных массивов: дополняем до expectedSize дефолтами
        // (уже не нужно — парсер/генератор обеспечивает правильный размер)
        return arr;
    }

    /** Создаёт фиксированный массив, заполненный значением. */
    static filled<T>(size: number, value: T, fixed: boolean): IdylArray<T> {
        const data: T[] = [];
        for (let i = 0; i < size; i++) {
            // Глубокое копирование для объектов не требуется —
            // примитивы копируются по значению.
            data.push(value);
        }
        return new IdylArray<T>(data, fixed);
    }

    /** Создаёт пустой динамический массив. */
    static empty<T>(fixed: boolean): IdylArray<T> {
        return new IdylArray<T>([], fixed);
    }

    // ── Доступ к элементам ───────────────────────────────────────────

    get(index: number, file: string, line: number): T {
        this.checkBounds(index, file, line);
        return this.data[index];
    }

    set(index: number, value: T, file: string, line: number): void {
        this.checkBounds(index, file, line);
        this.data[index] = value;
    }

    private checkBounds(index: number, file: string, line: number): void {
        if (index < 0 || index >= this.data.length) {
            const valid = this.data.length > 0
                ? `valid indices 0-${this.data.length - 1}`
                : 'array is empty';
            throw new IdylRuntimeError(file, line,
                `array index ${index} out of bounds (size ${this.data.length}, ${valid})`);
        }
    }

    // ── Длина ───────────────────────────────────────────────────────

    length(): number {
        return this.data.length;
    }

    // ── Методы, общие для array и dyn_array ─────────────────────────

    contains(value: T): boolean {
        return this.data.includes(value);
    }

    find(value: T): number {
        return this.data.indexOf(value);
    }

    count(value: T): number {
        let c = 0;
        for (const el of this.data) {
            if (el === value) c++;
        }
        return c;
    }

    reverse(): void {
        this.data.reverse();
    }

    sort(): void {
        this.data.sort((a, b) => {
            if (typeof a === 'number' && typeof b === 'number') return a - b;
            if (typeof a === 'string' && typeof b === 'string') return a.localeCompare(b);
            return 0;
        });
    }

    // ── Методы только для dyn_array ─────────────────────────────────

    private requireDynamic(method: string): void {
        if (this.fixed) {
            throw new Error(`'${method}' is only available on dynamic arrays`);
        }
    }

    add(value: T): void {
        this.requireDynamic('add');
        this.data.push(value);
    }

    removeAt(index: number, file: string, line: number): void {
        this.requireDynamic('remove_at');
        this.checkBounds(index, file, line);
        this.data.splice(index, 1);
    }

    resize(newSize: number): void {
        this.requireDynamic('resize');
        if (newSize < this.data.length) {
            this.data.length = newSize;
        } else {
            // Заполняем дефолтным значением на основе существующих элементов
            const def = this.data.length > 0 ? defaultOf(this.data[0]) : 0;
            while (this.data.length < newSize) {
                this.data.push(def as T);
            }
        }
    }

    insert(index: number, value: T): void {
        this.requireDynamic('insert');
        this.data.splice(index, 0, value);
    }

    join(other: IdylArray<T>): void {
        this.requireDynamic('join');
        this.data.push(...other.data);
    }

    clear(): void {
        this.requireDynamic('clear');
        this.data.length = 0;
    }

    pop(file: string, line: number): T {
        this.requireDynamic('pop');
        if (this.data.length === 0) {
            throw new IdylRuntimeError(file, line,
                'cannot pop from empty array');
        }
        return this.data.pop()!;
    }

    // ── Получение внутреннего массива (для max/min/sum/avg) ──────────

    getData(): readonly T[] {
        return this.data;
    }

    // ── Строковое представление (для console.write) ─────────────────

    toString(): string {
        const inner = this.data.map(v => {
            if (typeof v === 'string') return `"${v}"`;
            if (v instanceof IdylArray) return v.toString();
            return String(v);
        }).join(', ');
        return `[${inner}]`;
    }
}

/** Определяет дефолтное значение по типу существующего элемента. */
function defaultOf(sample: unknown): unknown {
    if (typeof sample === 'number') return 0;
    if (typeof sample === 'string') return '';
    if (typeof sample === 'boolean') return false;
    return null;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 3 — BUILT-IN FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────────

function idylDiv(a: number, b: number, file: string, line: number): number {
    if (b === 0) {
        throw new IdylRuntimeError(file, line, 'division by zero');
    }
    return Math.trunc(a / b);
}

function idylMod(a: number, b: number, file: string, line: number): number {
    if (b === 0) {
        throw new IdylRuntimeError(file, line, 'division by zero (mod)');
    }
    return a % b;
}

function idylToInt(value: unknown, file: string, line: number): number {
    if (typeof value === 'number') {
        return Math.trunc(value);
    }
    if (typeof value === 'string') {
        const n = parseInt(value, 10);
        if (isNaN(n)) {
            throw new IdylRuntimeError(file, line,
                `'to_int' cannot convert "${value}" to integer`);
        }
        return n;
    }
    throw new IdylRuntimeError(file, line,
        `'to_int' received unsupported type`);
}

function idylToFloat(value: unknown, file: string, line: number): number {
    if (typeof value === 'number') {
        return value;
    }
    if (typeof value === 'string') {
        const n = parseFloat(value);
        if (isNaN(n)) {
            throw new IdylRuntimeError(file, line,
                `'to_float' cannot convert "${value}" to float`);
        }
        return n;
    }
    throw new IdylRuntimeError(file, line,
        `'to_float' received unsupported type`);
}

function idylToString(value: unknown): string {
    if (value instanceof IdylArray) return value.toString();
    if (typeof value === 'boolean') return value ? 'true' : 'false';
    return String(value);
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 4 — ARRAY AGGREGATE FUNCTIONS
// ─────────────────────────────────────────────────────────────────────────────

function idylMax(arr: IdylArray<number>): number {
    const data = arr.getData();
    if (data.length === 0) return 0;
    let m = data[0];
    for (let i = 1; i < data.length; i++) {
        if (data[i] > m) m = data[i];
    }
    return m;
}

function idylMin(arr: IdylArray<number>): number {
    const data = arr.getData();
    if (data.length === 0) return 0;
    let m = data[0];
    for (let i = 1; i < data.length; i++) {
        if (data[i] < m) m = data[i];
    }
    return m;
}

function idylSum(arr: IdylArray<number>): number {
    const data = arr.getData();
    let s = 0;
    for (const v of data) s += v;
    return s;
}

function idylAvg(arr: IdylArray<number>): number {
    const data = arr.getData();
    if (data.length === 0) return 0;
    let s = 0;
    for (const v of data) s += v;
    return s / data.length;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 5 — STRING UTILITIES
// ─────────────────────────────────────────────────────────────────────────────

function strCharAt(s: string, index: number, file: string, line: number): string {
    if (index < 0 || index >= s.length) {
        const valid = s.length > 0
            ? `valid indices 0-${s.length - 1}`
            : 'string is empty';
        throw new IdylRuntimeError(file, line,
            `string index ${index} out of bounds (length ${s.length}, ${valid})`);
    }
    return s[index];
}

function strContains(s: string, search: string): boolean {
    return s.includes(search);
}

function strFind(s: string, search: string): number {
    return s.indexOf(search);
}

function strCount(s: string, search: string): number {
    if (search.length === 0) return 0;
    let count = 0;
    let pos = 0;
    while (true) {
        const idx = s.indexOf(search, pos);
        if (idx === -1) break;
        count++;
        pos = idx + search.length;
    }
    return count;
}

/**
 * substring(start, count) — берёт count символов начиная с позиции start.
 * Если count не указан — до конца строки.
 * Отрицательный start → 0.
 */
function strSubstring(s: string, start: number, count?: number): string {
    if (start < 0) start = 0;
    if (count === undefined) {
        return s.substring(start);
    }
    return s.substring(start, start + count);
}

function strReplace(s: string, oldStr: string, newStr: string): string {
    // Заменяет ВСЕ вхождения (регистрозависимо)
    return s.split(oldStr).join(newStr);
}

function strSplit(s: string, delimiter: string): IdylArray<string> {
    const parts = s.split(delimiter);
    return IdylArray.from(parts, -1, false);
}

function strTrim(s: string): string {
    // Удаляет \n, \t, \r, пробелы с обоих концов
    return s.replace(/^[\s\n\r\t\0]+|[\s\n\r\t\0]+$/g, '');
}

function strIsInt(s: string): boolean {
    return /^-?\d+$/.test(s.trim());
}

function strIsFloat(s: string): boolean {
    const trimmed = s.trim();
    if (trimmed === '') return false;
    const n = Number(trimmed);
    return !isNaN(n) && isFinite(n);
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 6 — CONSOLE MODULE
// ─────────────────────────────────────────────────────────────────────────────

export interface ConsoleIO {
    /** Вызывается для вывода текста. */
    print(text: string): void;
    /** Вызывается для запроса строки у пользователя. */
    readLine(): Promise<string>;
}

function createConsoleModule(io: ConsoleIO) {
    let precision: number | null = null;

    function formatValue(v: unknown): string {
        if (v instanceof IdylArray) return v.toString();
        if (typeof v === 'number' && precision !== null) {
            return Number(v.toFixed(precision)).toString();
        }
        if (typeof v === 'boolean') return v ? 'true' : 'false';
        return String(v);
    }

    return {
        write(...args: unknown[]): void {
            const text = args.map(formatValue).join('');
            io.print(text);
        },

        writeln(...args: unknown[]): void {
            const text = args.map(formatValue).join('') + '\n';
            io.print(text);
        },

        async getInt(file: string, line: number): Promise<number> {
            const raw = await io.readLine();
            const trimmed = raw.trim();
            const n = parseInt(trimmed, 10);
            if (isNaN(n) || !(/^-?\d+$/.test(trimmed))) {
                throw new IdylRuntimeError(file, line,
                    `cannot convert input to 'int' (expected integer, got "${trimmed}")`);
            }
            return n;
        },

        async getFloat(file: string, line: number): Promise<number> {
            const raw = await io.readLine();
            const trimmed = raw.trim();
            const n = parseFloat(trimmed);
            if (isNaN(n)) {
                throw new IdylRuntimeError(file, line,
                    `cannot convert input to 'float' (expected number, got "${trimmed}")`);
            }
            return n;
        },

        async getString(): Promise<string> {
            return io.readLine();
        },

        setPrecision(digits: number): void {
            precision = digits > 0 ? digits : null;
        },
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 7 — MATH MODULE
// ─────────────────────────────────────────────────────────────────────────────

function createMathModule() {
    return {
        pi: Math.PI,
        e: Math.E,

        abs(x: number): number {
            return Math.abs(x);
        },

        round(x: number, digits?: number): number {
            if (digits === undefined) return Math.round(x);
            const factor = Math.pow(10, digits);
            return Math.round(x * factor) / factor;
        },

        floor(x: number, digits?: number): number {
            if (digits === undefined) return Math.floor(x);
            const factor = Math.pow(10, digits);
            return Math.floor(x * factor) / factor;
        },

        ceil(x: number, digits?: number): number {
            if (digits === undefined) return Math.ceil(x);
            const factor = Math.pow(10, digits);
            return Math.ceil(x * factor) / factor;
        },

        pow(base: number, exp: number): number {
            return Math.pow(base, exp);
        },

        sqrt(x: number, file: string, line: number): number {
            if (x < 0) {
                throw new IdylRuntimeError(file, line,
                    `math.sqrt argument must be >= 0 (got ${x})`);
            }
            return Math.sqrt(x);
        },

        clamp(min: number, val: number, max: number): number {
            return Math.max(min, Math.min(val, max));
        },

        asin(x: number, file: string, line: number): number {
            if (x < -1 || x > 1) {
                throw new IdylRuntimeError(file, line,
                    `math.asin argument must be between -1 and 1 (got ${x})`);
            }
            return Math.asin(x);
        },

        acos(x: number, file: string, line: number): number {
            if (x < -1 || x > 1) {
                throw new IdylRuntimeError(file, line,
                    `math.acos argument must be between -1 and 1 (got ${x})`);
            }
            return Math.acos(x);
        },

        toRadians(deg: number): number {
            return deg * (Math.PI / 180);
        },

        toDegrees(rad: number): number {
            return rad * (180 / Math.PI);
        },

        log(x: number, file: string, line: number): number {
            if (x <= 0) {
                throw new IdylRuntimeError(file, line,
                    `math.log argument must be > 0 (got ${x})`);
            }
            return Math.log(x);
        },

        log10(x: number, file: string, line: number): number {
            if (x <= 0) {
                throw new IdylRuntimeError(file, line,
                    `math.log10 argument must be > 0 (got ${x})`);
            }
            return Math.log10(x);
        },
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 8 — RANDOM MODULE (seedable PRNG)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Mulberry32 — простой и быстрый 32-битный PRNG с сидом.
 * Период: 2^32.  Достаточен для учебных целей.
 */
function mulberry32(seed: number): () => number {
    let state = seed | 0;
    return function (): number {
        state = (state + 0x6D2B79F5) | 0;
        let t = Math.imul(state ^ (state >>> 15), 1 | state);
        t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
        return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
    };
}

function createRandomModule() {
    // По умолчанию: случайный сид
    let rng = mulberry32(Date.now() ^ (Math.random() * 0xFFFFFFFF));

    return {
        createInt(min: number, max: number): number {
            return Math.floor(rng() * (max - min + 1)) + min;
        },

        createFloat(min: number, max: number): number {
            return rng() * (max - min) + min;
        },

        chooseFrom(source: string | IdylArray<unknown>): unknown {
            if (typeof source === 'string') {
                if (source.length === 0) return '\0';
                const idx = Math.floor(rng() * source.length);
                return source[idx];
            }
            // IdylArray
            const data = source.getData();
            if (data.length === 0) return null;
            const idx = Math.floor(rng() * data.length);
            return data[idx];
        },

        setSeed(seed: number): void {
            rng = mulberry32(seed);
        },
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 9 — TIME MODULE
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Обёртка над JS Date, предоставляющая API time.stamp.
 */
class TimeStamp {
    private readonly date: Date;

    constructor(date: Date) {
        this.date = date;
    }

    year(): number   { return this.date.getFullYear(); }
    month(): number  { return this.date.getMonth() + 1; } // 1–12, не 0–11
    day(): number    { return this.date.getDate(); }
    hour(): number   { return this.date.getHours(); }
    minute(): number { return this.date.getMinutes(); }
    second(): number { return this.date.getSeconds(); }

    /** День недели: 0 = воскресенье, 6 = суббота. */
    weekDay(): number { return this.date.getDay(); }

    /** UNIX timestamp в секундах. */
    unix(): number {
        return Math.floor(this.date.getTime() / 1000);
    }

    toString(): string {
        const pad = (n: number) => n.toString().padStart(2, '0');
        const d = this.date;
        return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())} ` +
               `${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
    }
}

function createTimeModule() {
    return {
        now(): TimeStamp {
            return new TimeStamp(new Date());
        },

        async sleep(seconds: number): Promise<void> {
            return new Promise(resolve =>
                setTimeout(resolve, Math.max(0, seconds * 1000)));
        },

        fromUnix(timestamp: number): TimeStamp {
            return new TimeStamp(new Date(timestamp * 1000));
        },
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 10 — FILE MODULE (virtual filesystem)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Интерфейс виртуальной файловой системы.
 * В веб-среде реализуется через Map<string, string> в памяти.
 * IDE может предзагружать файлы через этот интерфейс.
 */
export interface VirtualFS {
    read(filename: string): string | null;
    write(filename: string, content: string): void;
    exists(filename: string): boolean;
}

/** Простейшая реализация VFS в памяти. */
export class InMemoryFS implements VirtualFS {
    private files: Map<string, string> = new Map();

    /** Предзагружает файл (для тестирования / IDE). */
    preload(filename: string, content: string): void {
        this.files.set(filename, content);
    }

    read(filename: string): string | null {
        return this.files.get(filename) ?? null;
    }

    write(filename: string, content: string): void {
        this.files.set(filename, content);
    }

    exists(filename: string): boolean {
        return this.files.has(filename);
    }
}

/** Входной поток для чтения файла построчно. */
class FileInputStream {
    private lines: string[];
    private pos: number = 0;

    constructor(content: string) {
        // Разбиваем по \n, сохраняя \n на концах (кроме последней)
        this.lines = content.split('\n');
    }

    readLine(): string {
        if (this.pos >= this.lines.length) return '';
        const line = this.lines[this.pos];
        this.pos++;
        // Добавляем \n ко всем строкам кроме последней
        if (this.pos < this.lines.length) {
            return line + '\n';
        }
        return line;
    }

    hasNextLine(): boolean {
        return this.pos < this.lines.length;
    }

    close(): void {
        // Noop в виртуальной FS, но сохраняем для правильных привычек.
    }
}

/** Выходной поток для записи в файл. */
class FileOutputStream {
    private buffer: string = '';
    private readonly fs: VirtualFS;
    private readonly filename: string;

    constructor(fs: VirtualFS, filename: string) {
        this.fs = fs;
        this.filename = filename;
    }

    writeLine(...args: unknown[]): void {
        for (const arg of args) {
            this.buffer += String(arg);
        }
    }

    close(): void {
        this.fs.write(this.filename, this.buffer);
    }
}

function createFileModule(fs: VirtualFS) {
    return {
        open(
            filename: string, mode: string, file: string, line: number,
        ): FileInputStream | FileOutputStream {
            if (mode === 'read') {
                const content = fs.read(filename);
                if (content === null) {
                    throw new IdylRuntimeError(file, line,
                        `cannot open file "${filename}" for reading (file not found)`);
                }
                return new FileInputStream(content);
            }
            if (mode === 'write') {
                return new FileOutputStream(fs, filename);
            }
            throw new IdylRuntimeError(file, line,
                `unknown file mode "${mode}" (expected "read" or "write")`);
        },
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 11 — RUNTIME FACTORY
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Интерфейс объекта $rt, используемого сгенерированным JS-кодом.
 */
export interface IdylRuntime {
    // Обёртка массива
    IdylArray: typeof IdylArray;

    // Встроенные функции
    div:       typeof idylDiv;
    mod:       typeof idylMod;
    toInt:     typeof idylToInt;
    toFloat:   typeof idylToFloat;
    toString_: typeof idylToString;
    max:       typeof idylMax;
    min:       typeof idylMin;
    sum:       typeof idylSum;
    avg:       typeof idylAvg;

    // Строковые утилиты
    strCharAt:    typeof strCharAt;
    strContains:  typeof strContains;
    strFind:      typeof strFind;
    strCount:     typeof strCount;
    strSubstring: typeof strSubstring;
    strReplace:   typeof strReplace;
    strSplit:     typeof strSplit;
    strTrim:      typeof strTrim;
    strIsInt:     typeof strIsInt;
    strIsFloat:   typeof strIsFloat;

    // Библиотеки
    console: ReturnType<typeof createConsoleModule>;
    math:    ReturnType<typeof createMathModule>;
    random:  ReturnType<typeof createRandomModule>;
    time:    ReturnType<typeof createTimeModule>;
    file:    ReturnType<typeof createFileModule>;
}

/**
 * Параметры создания рантайма.
 */
export interface RuntimeOptions {
    /** Реализация консольного ввода-вывода. */
    console: ConsoleIO;
    /** Виртуальная файловая система (опционально). */
    fs?: VirtualFS;
}

/**
 * Создаёт объект $rt для передачи в сгенерированный JS-код.
 *
 * Использование:
 * ```typescript
 * const rt = createRuntime({
 *     console: {
 *         print: (text) => terminalElement.textContent += text,
 *         readLine: () => new Promise(resolve => { ... }),
 *     },
 * });
 *
 * const jsCode = codegen.generate(program);
 * const fn = new Function('$rt', jsCode);
 * await fn(rt);
 * ```
 */
export function createRuntime(options: RuntimeOptions): IdylRuntime {
    const fs = options.fs ?? new InMemoryFS();

    return {
        // Массивы
        IdylArray,

        // Встроенные функции
        div:       idylDiv,
        mod:       idylMod,
        toInt:     idylToInt,
        toFloat:   idylToFloat,
        toString_: idylToString,
        max:       idylMax,
        min:       idylMin,
        sum:       idylSum,
        avg:       idylAvg,

        // Строковые утилиты
        strCharAt,
        strContains,
        strFind,
        strCount,
        strSubstring,
        strReplace,
        strSplit,
        strTrim,
        strIsInt,
        strIsFloat,

        // Библиотеки
        console: createConsoleModule(options.console),
        math:    createMathModule(),
        random:  createRandomModule(),
        time:    createTimeModule(),
        file:    createFileModule(fs),
    };
}