// =============================================================================
// resolved-types.ts — система разрешённых типов Idyllium
// =============================================================================
//
// TypeNode (из ast.ts) — это СИНТАКСИЧЕСКОЕ представление типа: то, что
// написал программист.  ResolvedType — это СЕМАНТИЧЕСКОЕ представление:
// то, чем тип является после разрешения имён и проверок.
//
// Разница:
//   TypeNode:     { kind: 'ClassType', name: 'Point2D' }   — «какой-то Point2D»
//   ResolvedType: { tag: 'class', name: 'Point2D' }        — «класс Point2D существует»
//
// ResolvedType используется:
//   • семантическим анализатором — для проверки совместимости
//   • генератором кода — для выбора стратегии генерации
// =============================================================================

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 1 — TYPE DEFINITIONS
// ─────────────────────────────────────────────────────────────────────────────

export interface PrimRT {
    readonly tag: 'int' | 'float' | 'string' | 'char' | 'bool' | 'void';
}

export interface ArrayRT {
    readonly tag: 'array';
    readonly elementType: ResolvedType;
    readonly size: number;
}

export interface DynArrayRT {
    readonly tag: 'dyn_array';
    readonly elementType: ResolvedType;
}

export interface ClassRT {
    readonly tag: 'class';
    readonly name: string;
}

export interface QualifiedRT {
    readonly tag: 'qualified';
    readonly qualifier: string;
    readonly name: string;
}

/**
 * Тип функции / метода / лямбды.
 * Используется для хранения сигнатур в таблице символов.
 */
export interface FunctionRT {
    readonly tag: 'function';
    readonly paramTypes: FunctionParam[];
    readonly returnType: ResolvedType;
}

export interface FunctionParam {
    readonly name: string;
    readonly type: ResolvedType;
    readonly hasDefault: boolean;
}

/**
 * Тип-заглушка для ошибочных выражений.
 * Когда тип не удалось определить из-за ошибки, вместо `null`
 * возвращается ERROR_TYPE.  Это позволяет продолжить анализ
 * и подавить каскад вторичных ошибок: любая операция с ERROR_TYPE
 * тихо возвращает ERROR_TYPE (без новых ошибок).
 */
export interface ErrorRT {
    readonly tag: 'error';
}

/** Объединённый тип всех разрешённых типов. */
export type ResolvedType =
    | PrimRT
    | ArrayRT
    | DynArrayRT
    | ClassRT
    | QualifiedRT
    | FunctionRT
    | ErrorRT;


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 2 — SINGLETON CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

export const INT_TYPE:    PrimRT  = { tag: 'int'    };
export const FLOAT_TYPE:  PrimRT  = { tag: 'float'  };
export const STRING_TYPE: PrimRT  = { tag: 'string' };
export const CHAR_TYPE:   PrimRT  = { tag: 'char'   };
export const BOOL_TYPE:   PrimRT  = { tag: 'bool'   };
export const VOID_TYPE:   PrimRT  = { tag: 'void'   };
export const ERROR_TYPE:  ErrorRT = { tag: 'error'  };


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 3 — CONSTRUCTORS
// ─────────────────────────────────────────────────────────────────────────────

export function makeArrayType(elementType: ResolvedType, size: number): ArrayRT {
    return { tag: 'array', elementType, size };
}

export function makeDynArrayType(elementType: ResolvedType): DynArrayRT {
    return { tag: 'dyn_array', elementType };
}

export function makeClassType(name: string): ClassRT {
    return { tag: 'class', name };
}

export function makeQualifiedType(qualifier: string, name: string): QualifiedRT {
    return { tag: 'qualified', qualifier, name };
}

export function makeFunctionType(
    paramTypes: FunctionParam[],
    returnType: ResolvedType,
): FunctionRT {
    return { tag: 'function', paramTypes, returnType };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 4 — TYPE TO STRING (for error messages)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Возвращает человекочитаемое строковое представление типа.
 *
 * Примеры:
 *   int, float, string
 *   array<int, 5>
 *   dyn_array<string>
 *   Point2D
 *   time.stamp
 */
export function typeToString(t: ResolvedType): string {
    switch (t.tag) {
        case 'int':       return 'int';
        case 'float':     return 'float';
        case 'string':    return 'string';
        case 'char':      return 'char';
        case 'bool':      return 'bool';
        case 'void':      return 'void';
        case 'error':     return '<error>';
        case 'array':
            return `array<${typeToString(t.elementType)}, ${t.size}>`;
        case 'dyn_array':
            return `dyn_array<${typeToString(t.elementType)}>`;
        case 'class':
            return t.name;
        case 'qualified':
            return `${t.qualifier}.${t.name}`;
        case 'function': {
            const params = t.paramTypes.map(p => typeToString(p.type)).join(', ');
            return `function(${params}) -> ${typeToString(t.returnType)}`;
        }
    }
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 5 — TYPE EQUALITY (deep comparison)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Проверяет глубокое структурное равенство двух типов.
 *
 *   typesEqual(INT_TYPE, INT_TYPE)                            → true
 *   typesEqual(makeArrayType(INT_TYPE, 5), makeArrayType(INT_TYPE, 5)) → true
 *   typesEqual(INT_TYPE, FLOAT_TYPE)                          → false
 *   typesEqual(makeArrayType(INT_TYPE, 5), makeArrayType(INT_TYPE, 3)) → false
 */
export function typesEqual(a: ResolvedType, b: ResolvedType): boolean {
    if (a.tag !== b.tag) return false;

    switch (a.tag) {
        case 'int':
        case 'float':
        case 'string':
        case 'char':
        case 'bool':
        case 'void':
        case 'error':
            return true; // tag уже совпал

        case 'array': {
            const ba = b as ArrayRT;
            return a.size === ba.size && typesEqual(a.elementType, ba.elementType);
        }

        case 'dyn_array': {
            const bd = b as DynArrayRT;
            return typesEqual(a.elementType, bd.elementType);
        }

        case 'class': {
            const bc = b as ClassRT;
            return a.name === bc.name;
        }

        case 'qualified': {
            const bq = b as QualifiedRT;
            return a.qualifier === bq.qualifier && a.name === bq.name;
        }

        case 'function': {
            const bf = b as FunctionRT;
            if (a.paramTypes.length !== bf.paramTypes.length) return false;
            if (!typesEqual(a.returnType, bf.returnType)) return false;
            return a.paramTypes.every((p, i) => typesEqual(p.type, bf.paramTypes[i].type));
        }
    }
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 6 — TYPE COMPATIBILITY (assignment checking)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Можно ли присвоить значение типа `source` в переменную типа `target`?
 *
 * Правила:
 *   • Одинаковые типы — всегда можно.
 *   • int → float — можно (неявное расширение: 5 становится 5.0).
 *   • float → int — НЕЛЬЗЯ (потеря данных).
 *   • int → string — НЕЛЬЗЯ (нужен to_string()).
 *   • Все остальные несовпадения — НЕЛЬЗЯ.
 *   • ERROR_TYPE совместим с чем угодно (подавление каскадных ошибок).
 */
export function isAssignable(target: ResolvedType, source: ResolvedType): boolean {
    // Error recovery: не плодить ошибки, если тип уже ошибочен
    if (target.tag === 'error' || source.tag === 'error') return true;

    // Точное совпадение
    if (typesEqual(target, source)) return true;

    // int → float (неявное расширение)
    if (target.tag === 'float' && source.tag === 'int') return true;

    // dyn_array<T> → array<T, N>
    // Разрешаем присваивание литерала массива (который парсер/анализатор
    // типизирует как dyn_array) в статический массив.
    // Проверка количества элементов — в анализаторе.
    if (target.tag === 'array' && source.tag === 'dyn_array') {
        return isAssignable(target.elementType, source.elementType);
    }

    // array<T, N> → dyn_array<T>
    // Разрешаем присваивание статического массива в динамический.
    if (target.tag === 'dyn_array' && source.tag === 'array') {
        return isAssignable(target.elementType, source.elementType);
    }

    return false;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 7 — TYPE PREDICATES
// ─────────────────────────────────────────────────────────────────────────────

/** Является ли тип числовым (int или float)? */
export function isNumeric(t: ResolvedType): boolean {
    return t.tag === 'int' || t.tag === 'float';
}

/** Является ли тип массивом (статическим или динамическим)? */
export function isArrayLike(t: ResolvedType): boolean {
    return t.tag === 'array' || t.tag === 'dyn_array';
}

/** Является ли тип динамическим массивом? */
export function isDynArray(t: ResolvedType): boolean {
    return t.tag === 'dyn_array';
}

/** Является ли тип ошибочным? */
export function isError(t: ResolvedType): boolean {
    return t.tag === 'error';
}

/** Является ли тип void? */
export function isVoid(t: ResolvedType): boolean {
    return t.tag === 'void';
}

/**
 * Извлекает тип элемента массива.
 * Для не-массивных типов возвращает null.
 */
export function getElementType(t: ResolvedType): ResolvedType | null {
    if (t.tag === 'array') return t.elementType;
    if (t.tag === 'dyn_array') return t.elementType;
    return null;
}

/**
 * Определяет, является ли тип «числовым массивом»
 * (массив с элементами int или float).
 * Нужно для проверки аргументов max(), min(), sum(), avg().
 */
export function isNumericArray(t: ResolvedType): boolean {
    const el = getElementType(t);
    return el !== null && isNumeric(el);
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 8 — ARITHMETIC RESULT TYPES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Определяет тип результата арифметической операции.
 *
 * Правила Idyllium:
 *   • `/` ВСЕГДА возвращает float (даже int / int).
 *   • `+`, `-`, `*`: если оба операнда int → int; если хотя бы один float → float.
 *   • `+` для строк/символов: конкатенация → string.
 *   • Все прочие комбинации — ошибка (возвращает null).
 */
export function arithmeticResultType(
    left: ResolvedType,
    right: ResolvedType,
    op: '+' | '-' | '*' | '/',
): ResolvedType | null {
    // Error recovery
    if (left.tag === 'error' || right.tag === 'error') return ERROR_TYPE;

    // Деление ВСЕГДА → float
    if (op === '/') {
        if (isNumeric(left) && isNumeric(right)) return FLOAT_TYPE;
        return null;
    }

    // Конкатенация с `+`
    if (op === '+') {
        // string + string → string
        if (left.tag === 'string' && right.tag === 'string') return STRING_TYPE;
        // string + char → string
        if (left.tag === 'string' && right.tag === 'char') return STRING_TYPE;
        // char + string → string
        if (left.tag === 'char' && right.tag === 'string') return STRING_TYPE;
        // char + char → string
        if (left.tag === 'char' && right.tag === 'char') return STRING_TYPE;
    }

    // Числовая арифметика: +, -, *
    if (isNumeric(left) && isNumeric(right)) {
        // int op int → int
        if (left.tag === 'int' && right.tag === 'int') return INT_TYPE;
        // иначе → float
        return FLOAT_TYPE;
    }

    // Неподдерживаемая комбинация
    return null;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 9 — COMPARISON RESULT TYPES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Определяет, допустимо ли сравнение двух типов.
 * Все сравнения возвращают bool.
 *
 * Допустимые комбинации:
 *   • число с числом (int/float с int/float)
 *   • string с string
 *   • char с char
 *   • bool с bool (только == и !=)
 *   • класс с классом (одного типа, только == и !=)
 *
 * @param op  Оператор сравнения (для проверки ограничений < > <= >= для bool).
 * @returns   BOOL_TYPE если допустимо, null если нет.
 */
export function comparisonResultType(
    left: ResolvedType,
    right: ResolvedType,
    op: '==' | '!=' | '<' | '>' | '<=' | '>=',
): ResolvedType | null {
    if (left.tag === 'error' || right.tag === 'error') return BOOL_TYPE;

    // Числа: любые сравнения
    if (isNumeric(left) && isNumeric(right)) return BOOL_TYPE;

    // Строки: любые сравнения (лексикографические)
    if (left.tag === 'string' && right.tag === 'string') return BOOL_TYPE;

    // Символы: любые сравнения (по коду)
    if (left.tag === 'char' && right.tag === 'char') return BOOL_TYPE;

    // Bool: только == и !=
    if (left.tag === 'bool' && right.tag === 'bool') {
        if (op === '==' || op === '!=') return BOOL_TYPE;
        return null; // нельзя `true > false`
    }

    // Классы одного типа: только == и !=
    if (left.tag === 'class' && right.tag === 'class' && left.name === right.name) {
        if (op === '==' || op === '!=') return BOOL_TYPE;
        return null;
    }

    return null;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 10 — LOGICAL OPERATION TYPES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Проверяет допустимость логической операции.
 * Оба операнда должны быть bool.  Результат — bool.
 *
 * @returns BOOL_TYPE если допустимо, null если нет.
 */
export function logicalResultType(
    left: ResolvedType,
    right: ResolvedType,
): ResolvedType | null {
    if (left.tag === 'error' || right.tag === 'error') return BOOL_TYPE;
    if (left.tag === 'bool' && right.tag === 'bool') return BOOL_TYPE;
    return null;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 11 — DEFAULT VALUES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Возвращает строковое описание дефолтного значения для типа.
 * Используется в документации и сообщениях.
 */
export function defaultValueDescription(t: ResolvedType): string {
    switch (t.tag) {
        case 'int':       return '0';
        case 'float':     return '0.0';
        case 'bool':      return 'false';
        case 'char':      return "'\\0'";
        case 'string':    return '""';
        case 'array':     return `array of ${t.size} default values`;
        case 'dyn_array': return 'empty dynamic array';
        default:          return 'undefined';
    }
}