// =============================================================================
// errors.ts — система сбора и форматирования ошибок компиляции
// =============================================================================

/**
 * Серьёзность диагностического сообщения.
 */
export enum ErrorSeverity {
    ERROR   = 'error',
    WARNING = 'warning',
}

/**
 * Одна диагностика (ошибка или предупреждение).
 */
export interface CompileError {
    readonly file: string;
    readonly line: number;
    readonly severity: ErrorSeverity;
    readonly message: string;
}

/**
 * Коллектор ошибок — единая точка сбора диагностик для всего пайплайна
 * компиляции.  Передаётся в лексер, парсер, семантический анализатор.
 *
 * Позволяет продолжать компиляцию после первой ошибки, чтобы собрать
 * как можно больше диагностик за один запуск.
 */
export class ErrorCollector {
    private diagnostics: CompileError[] = [];
    private maxErrors: number;

    /**
     * @param maxErrors  Максимальное количество ошибок, после которого
     *                   новые ошибки не добавляются.  Предотвращает
     *                   лавину вторичных ошибок.  0 = без лимита.
     */
    constructor(maxErrors: number = 100) {
        this.maxErrors = maxErrors;
    }

    // ─── Добавление диагностик ──────────────────────────────────────────

    addError(file: string, line: number, message: string): void {
        if (this.maxErrors > 0 && this.errorCount() >= this.maxErrors) {
            return;
        }
        this.diagnostics.push({
            file,
            line,
            severity: ErrorSeverity.ERROR,
            message,
        });
    }

    addWarning(file: string, line: number, message: string): void {
        this.diagnostics.push({
            file,
            line,
            severity: ErrorSeverity.WARNING,
            message,
        });
    }

    // ─── Запросы ────────────────────────────────────────────────────────

    /** Есть ли хотя бы одна ошибка (не предупреждение)? */
    hasErrors(): boolean {
        return this.diagnostics.some(d => d.severity === ErrorSeverity.ERROR);
    }

    /** Количество ошибок (без предупреждений). */
    errorCount(): number {
        return this.diagnostics.filter(d => d.severity === ErrorSeverity.ERROR).length;
    }

    /** Общее количество диагностик. */
    totalCount(): number {
        return this.diagnostics.length;
    }

    /** Все диагностики (копия массива). */
    getAll(): CompileError[] {
        return [...this.diagnostics];
    }

    /** Только ошибки. */
    getErrors(): CompileError[] {
        return this.diagnostics.filter(d => d.severity === ErrorSeverity.ERROR);
    }

    /** Только предупреждения. */
    getWarnings(): CompileError[] {
        return this.diagnostics.filter(d => d.severity === ErrorSeverity.WARNING);
    }

    /** Достигнут ли лимит ошибок? */
    isOverflow(): boolean {
        return this.maxErrors > 0 && this.errorCount() >= this.maxErrors;
    }

    // ─── Форматирование ────────────────────────────────────────────────

    /**
     * Форматирует одну диагностику в строку вида:
     *   file.idyl:7: error: cannot assign 'float' value to 'int' variable
     */
    static formatOne(err: CompileError): string {
        return `${err.file}:${err.line}: ${err.severity}: ${err.message}`;
    }

    /**
     * Форматирует все диагностики, разделяя переносом строки.
     * Диагностики сортируются по файлу, затем по номеру строки.
     */
    format(): string {
        const sorted = [...this.diagnostics].sort((a, b) => {
            if (a.file !== b.file) return a.file.localeCompare(b.file);
            return a.line - b.line;
        });
        let result = sorted.map(ErrorCollector.formatOne).join('\n');
        if (this.isOverflow()) {
            result += `\n... too many errors (limit: ${this.maxErrors})`;
        }
        return result;
    }

    // ─── Сброс ─────────────────────────────────────────────────────────

    clear(): void {
        this.diagnostics = [];
    }
}