// =============================================================================
// tokens.ts — определения всех типов токенов языка Idyllium
// =============================================================================

export enum TokenType {
    // ===== Литералы =====
    INT_LITERAL,        // 42, 0, 255
    FLOAT_LITERAL,      // 3.14, 0.5
    STRING_LITERAL,     // "hello"
    CHAR_LITERAL,       // 'A', '\n'

    // ===== Ключевые слова: имена типов =====
    KW_INT,             // int
    KW_FLOAT,           // float
    KW_STRING,          // string
    KW_CHAR,            // char
    KW_BOOL,            // bool
    KW_VOID,            // void
    KW_ARRAY,           // array
    KW_DYN_ARRAY,       // dyn_array

    // ===== Ключевые слова: управление потоком =====
    KW_IF,              // if
    KW_ELSE,            // else
    KW_WHILE,           // while
    KW_DO,              // do
    KW_FOR,             // for
    KW_BREAK,           // break
    KW_CONTINUE,        // continue
    KW_RETURN,          // return

    // ===== Ключевые слова: функции и структура программы =====
    KW_FUNCTION,        // function
    KW_MAIN,            // main
    KW_USE,             // use

    // ===== Ключевые слова: логические операторы =====
    KW_AND,             // and
    KW_OR,              // or
    KW_XOR,             // xor
    KW_NOT,             // not

    // ===== Ключевые слова: булевы литералы =====
    KW_TRUE,            // true
    KW_FALSE,           // false

    // ===== Ключевые слова: ООП =====
    KW_CLASS,           // class
    KW_EXTENDS,         // extends
    KW_THIS,            // this
    KW_CONSTRUCTOR,     // constructor
    KW_DESTRUCTOR,      // destructor
    KW_PUBLIC,          // public
    KW_PRIVATE,         // private

    // ===== Ключевые слова: встроенные операции =====
    KW_DIV,             // div
    KW_MOD,             // mod

    // ===== Операторы: арифметика =====
    PLUS,               // +
    MINUS,              // -
    STAR,               // *
    SLASH,              // /

    // ===== Операторы: присваивание =====
    ASSIGN,             // =
    PLUS_ASSIGN,        // +=
    MINUS_ASSIGN,       // -=
    STAR_ASSIGN,        // *=
    SLASH_ASSIGN,       // /=

    // ===== Операторы: сравнение =====
    EQ,                 // ==
    NEQ,                // !=
    LT,                 // <
    GT,                 // >
    LTE,                // <=
    GTE,                // >=

    // ===== Разделители =====
    LPAREN,             // (
    RPAREN,             // )
    LBRACE,             // {
    RBRACE,             // }
    LBRACKET,           // [
    RBRACKET,           // ]
    COMMA,              // ,
    SEMICOLON,          // ;
    DOT,                // .
    COLON,              // :
    TILDE,              // ~

    // ===== Идентификатор =====
    IDENTIFIER,

    // ===== Конец файла =====
    EOF,
}

/**
 * Единичный токен, порождаемый лексером.
 *
 * value — обработанное значение:
 *   - для STRING_LITERAL / CHAR_LITERAL escape-последовательности уже
 *     раскрыты (\n → реальный перенос строки и т.д.)
 *   - для INT_LITERAL / FLOAT_LITERAL — строковое представление числа
 *   - для ключевых слов и операторов — исходный текст ("if", "+=", …)
 *   - для IDENTIFIER — имя идентификатора
 */
export interface Token {
    readonly type: TokenType;
    readonly value: string;
    readonly line: number;
    readonly file: string;
}

