/**
 * Возвращает человеко-читаемое название типа токена
 * для использования в сообщениях об ошибках.
 *
 * Примеры:
 *   tokenTypeName(TokenType.INT_LITERAL)  → "integer"
 *   tokenTypeName(TokenType.PLUS)         → "'+'"
 *   tokenTypeName(TokenType.KW_IF)        → "'if'"
 *   tokenTypeName(TokenType.EOF)          → "end of file"
 */
export function tokenTypeName(type: TokenType): string {
    return TOKEN_DISPLAY[type] ?? 'unknown';
}

/**
 * Возвращает display-имя конкретного токена.
 * Для литералов и идентификаторов включает значение, для остальных —
 * стандартное display-имя типа.
 *
 * Примеры:
 *   tokenDisplayValue({ type: IDENTIFIER, value: "x", ... })  → "'x'"
 *   tokenDisplayValue({ type: INT_LITERAL, value: "42", ... }) → "42"
 *   tokenDisplayValue({ type: PLUS, value: "+", ... })         → "'+'"
 */
export function tokenDisplayValue(token: Token): string {
    switch (token.type) {
        case TokenType.IDENTIFIER:
            return `'${token.value}'`;
        case TokenType.INT_LITERAL:
        case TokenType.FLOAT_LITERAL:
            return token.value;
        case TokenType.STRING_LITERAL:
            return `"${token.value}"`;
        case TokenType.CHAR_LITERAL:
            return `'${token.value}'`;
        default:
            return tokenTypeName(token.type);
    }
}