// =============================================================================
// editor.ts — кастомный редактор кода
// =============================================================================

import { highlightToHTML } from './highlighter';

export interface EditorOptions {
    initialValue?: string;
    tabSize?: number;
    fontSize?: number;
    lineHeight?: number;
}

/**
 * Простой редактор кода с подсветкой синтаксиса.
 *
 * Архитектура:
 *   • textarea — невидимый, принимает ввод и хранит текст
 *   • pre > code — отображает подсвеченный код поверх textarea
 *   • line-numbers — номера строк слева
 *
 * Textarea и pre синхронизируются по скроллу и содержимому.
 */
export class Editor {
    private container: HTMLElement;
    private wrapper: HTMLElement;
    private lineNumbers: HTMLElement;
    private textarea: HTMLTextAreaElement;
    private highlight: HTMLElement;
    private pre: HTMLPreElement;

    private tabSize: number;
    private fontSize: number;
    private lineHeight: number;

    private undoStack: string[] = [];
    private redoStack: string[] = [];
    private lastSavedValue: string = '';

    constructor(container: HTMLElement, options: EditorOptions = {}) {
        this.container = container;
        this.tabSize = options.tabSize ?? 4;
        this.fontSize = options.fontSize ?? 15;
        this.lineHeight = options.lineHeight ?? 1.6;

        // ── Создаём DOM-структуру ────────────────────────────────────
        this.container.innerHTML = '';
        this.container.classList.add('editor-container');

        // Номера строк
        this.lineNumbers = document.createElement('div');
        this.lineNumbers.className = 'editor-line-numbers';
        this.container.appendChild(this.lineNumbers);

        // Обёртка для textarea и подсветки
        this.wrapper = document.createElement('div');
        this.wrapper.className = 'editor-wrapper';
        this.container.appendChild(this.wrapper);

        // Подсветка (pre > code)
        this.pre = document.createElement('pre');
        this.pre.className = 'editor-highlight';
        this.highlight = document.createElement('code');
        this.pre.appendChild(this.highlight);
        this.wrapper.appendChild(this.pre);

        // Textarea (невидимый, поверх подсветки)
        this.textarea = document.createElement('textarea');
        this.textarea.className = 'editor-textarea';
        this.textarea.spellcheck = false;
        this.textarea.autocomplete = 'off';
        this.textarea.setAttribute('autocapitalize', 'off');
        this.textarea.setAttribute('autocorrect', 'off');
        this.wrapper.appendChild(this.textarea);

        // ── Применяем стили ──────────────────────────────────────────
        this.applyStyles();

        // ── Обработчики событий ──────────────────────────────────────
        this.textarea.addEventListener('input', () => this.onInput());
        this.textarea.addEventListener('scroll', () => this.syncScroll());
        this.textarea.addEventListener('keydown', (e) => this.onKeyDown(e));

        // ── Начальное значение ───────────────────────────────────────
        const initial = options.initialValue ?? '';
        this.textarea.value = initial;
        this.lastSavedValue = initial;
        this.pushUndo();
        this.updateHighlight();
        this.updateLineNumbers();
    }

    // =====================================================================
    //  Public API
    // =====================================================================

    getValue(): string {
        return this.textarea.value;
    }

    setValue(value: string): void {
        this.textarea.value = value;
        this.pushUndo();
        this.updateHighlight();
        this.updateLineNumbers();
    }

    focus(): void {
        this.textarea.focus();
    }

    setFontSize(size: number): void {
        this.fontSize = size;
        this.applyStyles();
        this.updateLineNumbers();
    }

    setLineHeight(height: number): void {
        this.lineHeight = height;
        this.applyStyles();
        this.updateLineNumbers();
    }

    /**
     * Подсвечивает строки с ошибками.
     */
    highlightErrors(lines: number[]): void {
        // Сбрасываем предыдущие
        this.lineNumbers.querySelectorAll('.line-error').forEach(el => {
            el.classList.remove('line-error');
        });

        // Подсвечиваем новые
        for (const line of lines) {
            const lineEl = this.lineNumbers.children[line - 1] as HTMLElement | undefined;
            if (lineEl) {
                lineEl.classList.add('line-error');
            }
        }
    }

    clearErrors(): void {
        this.lineNumbers.querySelectorAll('.line-error').forEach(el => {
            el.classList.remove('line-error');
        });
    }

    // =====================================================================
    //  Private methods
    // =====================================================================

    private applyStyles(): void {
        const fontFamily = "'JetBrains Mono', 'Fira Code', 'Cascadia Code', 'Consolas', monospace";
        const styles = `
            font-family: ${fontFamily};
            font-size: ${this.fontSize}px;
            line-height: ${this.lineHeight};
            tab-size: ${this.tabSize};
        `;

        this.textarea.style.cssText += styles;
        this.pre.style.cssText += styles;
        this.lineNumbers.style.cssText += `
            font-family: ${fontFamily};
            font-size: ${this.fontSize}px;
            line-height: ${this.lineHeight};
        `;
    }

    private onInput(): void {
        this.updateHighlight();
        this.updateLineNumbers();
        this.pushUndo();
    }

    private updateHighlight(): void {
        const code = this.textarea.value;
        // Добавляем пробел в конец, чтобы высота совпадала
        this.highlight.innerHTML = highlightToHTML(code) + '\n ';
    }

    private updateLineNumbers(): void {
        const lines = this.textarea.value.split('\n').length;
        let html = '';
        for (let i = 1; i <= lines; i++) {
            html += `<div class="line-number">${i}</div>`;
        }
        this.lineNumbers.innerHTML = html;
    }

    private syncScroll(): void {
        this.pre.scrollTop = this.textarea.scrollTop;
        this.pre.scrollLeft = this.textarea.scrollLeft;
        this.lineNumbers.scrollTop = this.textarea.scrollTop;
    }

    private onKeyDown(e: KeyboardEvent): void {
        // ── Tab → вставка пробелов ──────────────────────────────────
        if (e.key === 'Tab') {
            e.preventDefault();
            const start = this.textarea.selectionStart;
            const end = this.textarea.selectionEnd;
            const value = this.textarea.value;
            const spaces = ' '.repeat(this.tabSize);

            this.textarea.value = value.substring(0, start) + spaces + value.substring(end);
            this.textarea.selectionStart = this.textarea.selectionEnd = start + this.tabSize;

            this.onInput();
        }

        // ── Enter → авто-отступ ─────────────────────────────────────
        if (e.key === 'Enter') {
            e.preventDefault();
            const start = this.textarea.selectionStart;
            const value = this.textarea.value;

            // Находим начало текущей строки
            let lineStart = start;
            while (lineStart > 0 && value[lineStart - 1] !== '\n') {
                lineStart--;
            }

            // Считаем отступ текущей строки
            let indent = '';
            let i = lineStart;
            while (i < value.length && (value[i] === ' ' || value[i] === '\t')) {
                indent += value[i];
                i++;
            }

            // Если предыдущий непробельный символ — '{', добавляем отступ
            const beforeCursor = value.substring(0, start).trimEnd();
            if (beforeCursor.endsWith('{')) {
                indent += ' '.repeat(this.tabSize);
            }

            const insertion = '\n' + indent;
            this.textarea.value =
                value.substring(0, start) + insertion + value.substring(this.textarea.selectionEnd);
            this.textarea.selectionStart = this.textarea.selectionEnd = start + insertion.length;

            this.onInput();
        }

        // ── Ctrl+Z → undo ───────────────────────────────────────────
        if (e.ctrlKey && e.key === 'z' && !e.shiftKey) {
            e.preventDefault();
            this.undo();
        }

        // ── Ctrl+Shift+Z или Ctrl+Y → redo ──────────────────────────
        if ((e.ctrlKey && e.shiftKey && e.key === 'Z') || (e.ctrlKey && e.key === 'y')) {
            e.preventDefault();
            this.redo();
        }
    }

    // ── Undo / Redo ─────────────────────────────────────────────────────

    private pushUndo(): void {
        const current = this.textarea.value;
        if (this.undoStack.length === 0 || this.undoStack[this.undoStack.length - 1] !== current) {
            this.undoStack.push(current);
            if (this.undoStack.length > 100) {
                this.undoStack.shift();
            }
            this.redoStack = [];
        }
    }

    private undo(): void {
        if (this.undoStack.length > 1) {
            const current = this.undoStack.pop()!;
            this.redoStack.push(current);
            const prev = this.undoStack[this.undoStack.length - 1];
            this.textarea.value = prev;
            this.updateHighlight();
            this.updateLineNumbers();
        }
    }

    private redo(): void {
        if (this.redoStack.length > 0) {
            const next = this.redoStack.pop()!;
            this.undoStack.push(next);
            this.textarea.value = next;
            this.updateHighlight();
            this.updateLineNumbers();
        }
    }
}