// =============================================================================
// lexer.ts — лексический анализатор языка Idyllium
// =============================================================================
//
// Превращает исходный текст в плоский массив токенов.
//
// Обрабатывает:
//   • пробелы, табуляцию, \r, \n
//   • однострочные комментарии   //
//   • блочные комментарии         /* … */
//   • строковые литералы          "…"  с escape-последовательностями
//   • символьные литералы         '…'  (ровно один символ / escape)
//   • целые литералы              42
//   • дробные литералы            3.14
//   • ключевые слова              if, while, function, class, …
//   • идентификаторы              myVar, счётчик, _temp  (Unicode-safe)
//   • операторы                   +  +=  ==  !=  <=  …
//   • разделители                 (  )  {  }  [  ]  ,  ;  .  :  ~
//
// При обнаружении ошибки лексер регистрирует её в ErrorCollector и
// продолжает работу, чтобы обнаружить как можно больше ошибок за один
// проход.  Результирующий массив токенов ВСЕГДА завершается EOF.
// =============================================================================

import { Token, TokenType, KEYWORDS } from './tokens';
import { ErrorCollector }             from './errors';

export class Lexer {

    // ─── Неизменяемые параметры ─────────────────────────────────────────
    private readonly source: string;
    private readonly file:   string;
    private readonly errors: ErrorCollector;

    // ─── Изменяемое состояние ───────────────────────────────────────────

    /** Индекс текущего символа в `source`. */
    private pos: number = 0;

    /** Номер текущей строки (считается с 1). */
    private line: number = 1;

    /**
     * Номер строки, на которой начался текущий токен.
     * Устанавливается в `tokenize()` перед каждым вызовом `scanToken()`.
     * Используется в `emit()` — токен получает номер строки своего начала,
     * а не конца (важно для многосимвольных токенов).
     */
    private startLine: number = 1;

    /** Накопленные токены. */
    private tokens: Token[] = [];

    // ═════════════════════════════════════════════════════════════════════
    //  Конструктор
    // ═════════════════════════════════════════════════════════════════════

    /**
     * @param source  Полный текст одного файла.
     * @param file    Имя файла (для сообщений об ошибках).
     * @param errors  Общий коллектор диагностик.
     */
    constructor(source: string, file: string, errors: ErrorCollector) {
        this.source = source;
        this.file   = file;
        this.errors = errors;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Публичный API
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Выполняет лексический анализ.
     *
     * @returns  Массив токенов; последний элемент всегда `EOF`.
     *           Даже если исходник пуст или полон ошибок, массив
     *           будет содержать как минимум `[EOF]`.
     */
    tokenize(): Token[] {
        while (!this.isAtEnd()) {
            // 1. Пропустить все пробелы и комментарии
            this.skipWhitespaceAndComments();

            // 2. Если после пропуска достигнут конец — выходим
            if (this.isAtEnd()) break;

            // 3. Запомнить строку начала следующего токена
            this.startLine = this.line;

            // 4. Сканировать один токен
            this.scanToken();
        }

        // Финальный маркер конца файла
        this.tokens.push({
            type:  TokenType.EOF,
            value: '',
            line:  this.line,
            file:  this.file,
        });

        return this.tokens;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Навигация по символам
    // ═════════════════════════════════════════════════════════════════════

    /** Достигнут ли конец исходного текста? */
    private isAtEnd(): boolean {
        return this.pos >= this.source.length;
    }

    /**
     * Возвращает текущий символ **без** продвижения позиции.
     * При EOF возвращает `'\0'`.
     */
    private peek(): string {
        return this.isAtEnd() ? '\0' : this.source[this.pos];
    }

    /**
     * Возвращает символ, следующий за текущим, **без** продвижения.
     * При EOF возвращает `'\0'`.
     */
    private peekNext(): string {
        return this.pos + 1 >= this.source.length
            ? '\0'
            : this.source[this.pos + 1];
    }

    /**
     * Потребляет текущий символ, продвигает позицию и возвращает его.
     * Если символ — `'\n'`, увеличивает счётчик строк.
     */
    private advance(): string {
        const ch = this.source[this.pos];
        this.pos++;
        if (ch === '\n') this.line++;
        return ch;
    }

    /**
     * Потребляет текущий символ **только если** он совпадает с `expected`.
     *
     * @returns `true`, если символ был потреблён.
     */
    private match(expected: string): boolean {
        if (this.isAtEnd() || this.source[this.pos] !== expected) return false;
        this.advance();
        return true;
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Порождение токенов
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Добавляет готовый токен.
     * Номер строки берётся из `this.startLine`, который был зафиксирован
     * до начала сканирования текущего токена.
     */
    private emit(type: TokenType, value: string): void {
        this.tokens.push({
            type,
            value,
            line: this.startLine,
            file: this.file,
        });
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Пропуск пробелов и комментариев
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Продвигает позицию через любую комбинацию пробельных символов,
     * однострочных (//) и блочных комментариев.
     *
     * Вызывается перед каждым сканированием токена; при выходе
     * `this.peek()` указывает либо на начало следующего токена,
     * либо на конец файла.
     */
    private skipWhitespaceAndComments(): void {
        while (!this.isAtEnd()) {
            const ch = this.peek();

            // --- пробельные символы ---
            if (ch === ' ' || ch === '\t' || ch === '\r' || ch === '\n') {
                this.advance();
                continue;
            }

            // --- однострочный комментарий:  // … до конца строки ---
            if (ch === '/' && this.peekNext() === '/') {
                this.advance(); // первый  '/'
                this.advance(); // второй  '/'
                while (!this.isAtEnd() && this.peek() !== '\n') {
                    this.advance();
                }
                // '\n' НЕ потребляем — внешний цикл обработает его
                // на следующей итерации (и инкрементирует this.line)
                continue;
            }

            // --- блочный комментарий:  /* … */ ---
            if (ch === '/' && this.peekNext() === '*') {
                this.scanBlockComment();
                continue;
            }

            // Не пробел и не комментарий — конец «пустого пространства».
            break;
        }
    }

    /**
     * Сканирует блочный комментарий `/* … *​/`.
     *
     * Предусловие: `this.peek() === '/'` и `this.peekNext() === '*'`.
     *
     * Вложенные блочные комментарии **не** поддерживаются: первый
     * встреченный `*​/` закрывает комментарий.
     */
    private scanBlockComment(): void {
        const openLine = this.line;
        this.advance(); // '/'
        this.advance(); // '*'

        while (!this.isAtEnd()) {
            if (this.peek() === '*' && this.peekNext() === '/') {
                this.advance(); // '*'
                this.advance(); // '/'
                return;         // комментарий закрыт — выходим
            }
            this.advance();     // пропускаем тело комментария
        }

        // Достигнут конец файла, а закрывающий */ не встретился.
        this.errors.addError(this.file, openLine, 'unclosed block comment');
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Главный диспетчер
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Сканирует **один** токен, начинающийся с текущей позиции, и добавляет
     * его в `this.tokens` (через `emit`).
     *
     * Предусловие: `this.isAtEnd() === false`;
     *              пробелы и комментарии уже пропущены;
     *              `this.startLine` установлен.
     */
    private scanToken(): void {
        const ch = this.peek();

        // ── Строковый литерал "…" ────────────────────────────────────
        if (ch === '"') {
            this.scanString();
            return;
        }

        // ── Символьный литерал '…' ───────────────────────────────────
        if (ch === "'") {
            this.scanChar();
            return;
        }

        // ── Числовой литерал ─────────────────────────────────────────
        if (this.isDigit(ch)) {
            this.scanNumber();
            return;
        }

        // ── Идентификатор / ключевое слово ───────────────────────────
        if (this.isIdentStart(ch)) {
            this.scanIdentifier();
            return;
        }

        // ── Операторы и разделители ──────────────────────────────────
        //    Потребляем первый символ, затем определяем тип по нему
        //    (и, возможно, по следующему — для двусимвольных операторов).
        this.advance();

        switch (ch) {

            // ── Арифметика / составное присваивание ──────────────────
            case '+':
                if (this.match('=')) this.emit(TokenType.PLUS_ASSIGN,  '+=');
                else                 this.emit(TokenType.PLUS,         '+');
                break;

            case '-':
                if (this.match('=')) this.emit(TokenType.MINUS_ASSIGN, '-=');
                else                 this.emit(TokenType.MINUS,        '-');
                break;

            case '*':
                if (this.match('=')) this.emit(TokenType.STAR_ASSIGN,  '*=');
                else                 this.emit(TokenType.STAR,         '*');
                break;

            case '/':
                // На этом этапе '/' гарантированно НЕ является частью
                // комментария (те были обработаны в skipWhitespace…).
                if (this.match('=')) this.emit(TokenType.SLASH_ASSIGN, '/=');
                else                 this.emit(TokenType.SLASH,        '/');
                break;

            // ── Присваивание / равенство ─────────────────────────────
            case '=':
                if (this.match('=')) this.emit(TokenType.EQ,     '==');
                else                 this.emit(TokenType.ASSIGN, '=');
                break;

            // ── Неравенство (! допустим ТОЛЬКО перед =) ──────────────
            case '!':
                if (this.match('=')) {
                    this.emit(TokenType.NEQ, '!=');
                } else {
                    this.errors.addError(
                        this.file,
                        this.startLine,
                        "illegal character '!' (did you mean '!=' or 'not()'?)",
                    );
                }
                break;

            // ── Сравнение / угловые скобки (< <=  > >=) ─────────────
            case '<':
                if (this.match('=')) this.emit(TokenType.LTE, '<=');
                else                 this.emit(TokenType.LT,  '<');
                break;

            case '>':
                if (this.match('=')) this.emit(TokenType.GTE, '>=');
                else                 this.emit(TokenType.GT,  '>');
                break;

            // ── Разделители ──────────────────────────────────────────
            case '(': this.emit(TokenType.LPAREN,    '('); break;
            case ')': this.emit(TokenType.RPAREN,    ')'); break;
            case '{': this.emit(TokenType.LBRACE,    '{'); break;
            case '}': this.emit(TokenType.RBRACE,    '}'); break;
            case '[': this.emit(TokenType.LBRACKET,  '['); break;
            case ']': this.emit(TokenType.RBRACKET,  ']'); break;
            case ',': this.emit(TokenType.COMMA,     ','); break;
            case ';': this.emit(TokenType.SEMICOLON, ';'); break;
            case '.': this.emit(TokenType.DOT,       '.'); break;
            case ':': this.emit(TokenType.COLON,     ':'); break;
            case '~': this.emit(TokenType.TILDE,     '~'); break;

            // ── Незнакомый символ ─────────────────────────────────────
            default:
                this.errors.addError(
                    this.file,
                    this.startLine,
                    `illegal character '${ch}'`,
                );
                break;
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Строковый литерал  "…"
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Предусловие: `this.peek() === '"'`.
     *
     * Сканирует содержимое строки, раскрывая escape-последовательности.
     * Многострочные строки запрещены: встретив `'\n'` до закрывающей
     * кавычки, лексер фиксирует ошибку.
     *
     * Результат: один токен STRING_LITERAL, `value` которого содержит
     * уже раскрытые escape-последовательности (например `\n` → U+000A).
     */
    private scanString(): void {
        this.advance(); // потребляем открывающую "

        let value = '';

        while (!this.isAtEnd() && this.peek() !== '"') {

            // Перенос строки внутри строкового литерала — ошибка.
            if (this.peek() === '\n') {
                this.errors.addError(
                    this.file, this.startLine, 'unclosed string literal',
                );
                return; // не потребляем '\n' — следующий цикл tokenize
                        // увидит его и корректно обновит номер строки
            }

            // Escape-последовательность
            if (this.peek() === '\\') {
                const esc = this.scanEscapeSequence();
                if (esc !== null) value += esc;
                continue;
            }

            // Обычный символ
            value += this.advance();
        }

        // Проверяем, нашлась ли закрывающая кавычка
        if (this.isAtEnd()) {
            this.errors.addError(
                this.file, this.startLine, 'unclosed string literal',
            );
            return;
        }

        this.advance(); // потребляем закрывающую "
        this.emit(TokenType.STRING_LITERAL, value);
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Символьный литерал  '…'
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Предусловие: `this.peek() === "'"`.
     *
     * Ожидает ровно один символ (или одну escape-последовательность)
     * между одинарными кавычками.
     *
     * Ошибки:
     *   • пустой литерал  ''
     *   • незакрытый литерал
     *   • несколько символов  'abc'
     */
    private scanChar(): void {
        this.advance(); // потребляем открывающую '

        // ── Обработка пустого литерала  '' ───────────────────────────
        if (!this.isAtEnd() && this.peek() === "'") {
            this.advance(); // потребляем закрывающую '
            this.errors.addError(
                this.file, this.startLine, 'empty character literal',
            );
            return;
        }

        // ── Обработка внезапного конца строки / файла ────────────────
        if (this.isAtEnd() || this.peek() === '\n') {
            this.errors.addError(
                this.file, this.startLine, 'unclosed character literal',
            );
            return;
        }

        // ── Чтение одного символа / escape-последовательности ────────
        let value: string;

        if (this.peek() === '\\') {
            const esc = this.scanEscapeSequence();
            value = esc !== null ? esc : '\0';
        } else {
            value = this.advance();
        }

        // ── Ожидаем закрывающую одинарную кавычку ────────────────────
        if (!this.isAtEnd() && this.peek() === "'") {
            this.advance(); // потребляем закрывающую '
            this.emit(TokenType.CHAR_LITERAL, value);
            return;
        }

        // ── Ошибка: в литерале больше одного символа ─────────────────
        // Потребляем «лишние» символы до ' или конца строки, чтобы
        // лексер мог продолжить работу (error recovery).
        while (!this.isAtEnd() && this.peek() !== "'" && this.peek() !== '\n') {
            this.advance();
        }
        if (!this.isAtEnd() && this.peek() === "'") {
            this.advance(); // потребляем закрывающую '
        }

        this.errors.addError(
            this.file,
            this.startLine,
            'character literal must contain exactly one character',
        );
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Escape-последовательности  (общие для строк и символов)
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Предусловие: `this.peek() === '\\'`.
     *
     * Потребляет обратную косую и следующий за ней символ, возвращая
     * раскрытое значение.
     *
     * Поддерживаемые последовательности:
     *   \\n   → U+000A  (перенос строки)
     *   \\t   → U+0009  (табуляция)
     *   \\0   → U+0000  (нулевой символ)
     *   \\\\  → U+005C  (обратная косая)
     *   \\"   → U+0022  (двойная кавычка)
     *   \\'   → U+0027  (одинарная кавычка)
     *   \\e   → U+001B  (ESC — для ANSI-последовательностей)
     *
     * При неизвестной последовательности фиксируется ошибка, а символ
     * после `\` возвращается «как есть».
     *
     * @returns  Раскрытый символ, или `null` если произошла ошибка
     *           и возвращать нечего.
     */
    private scanEscapeSequence(): string | null {
        this.advance(); // потребляем '\'

        if (this.isAtEnd()) {
            this.errors.addError(
                this.file,
                this.line,
                'unexpected end of file in escape sequence',
            );
            return null;
        }

        const esc = this.advance();

        switch (esc) {
            case 'n':  return '\n';
            case 't':  return '\t';
            case '0':  return '\0';
            case '\\': return '\\';
            case '"':  return '"';
            case "'":  return "'";
            case 'e':  return '\x1b';   // ESC (для ANSI-цветов и пр.)
            default:
                this.errors.addError(
                    this.file,
                    this.startLine,
                    `unknown escape sequence '\\${esc}'`,
                );
                return esc; // возвращаем символ «как есть» для recovery
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Числовые литералы
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Предусловие: `this.isDigit(this.peek())`.
     *
     * Сканирует целый или дробный литерал.
     *
     * Правила:
     *   • `42`   → INT_LITERAL
     *   • `3.14` → FLOAT_LITERAL
     *   • `3.`   → INT_LITERAL `3` + DOT  (точка — отдельный токен)
     *   • `.5`   → DOT + INT_LITERAL `5`  (не попадёт сюда, т.к. '.'
     *              не является цифрой — scanToken обработает его как DOT)
     *
     * Число считается дробным, если после целой части стоит `.`,
     * за которой следует **хотя бы одна цифра**.
     *
     * После числа проверяется, не «прилипла» ли к нему буква
     * (например `123abc`).  Если да — фиксируется ошибка, а «суффикс»
     * потребляется для восстановления.
     */
    private scanNumber(): void {
        let numStr = '';

        // ── Целая часть ──────────────────────────────────────────────
        while (!this.isAtEnd() && this.isDigit(this.peek())) {
            numStr += this.advance();
        }

        // ── Дробная часть (опционально) ──────────────────────────────
        //    Проверяем: текущий символ — '.', а за ним — цифра.
        if (!this.isAtEnd() && this.peek() === '.' && this.isDigit(this.peekNext())) {
            numStr += this.advance(); // '.'
            while (!this.isAtEnd() && this.isDigit(this.peek())) {
                numStr += this.advance();
            }
            this.emit(TokenType.FLOAT_LITERAL, numStr);
        } else {
            this.emit(TokenType.INT_LITERAL, numStr);
        }

        // ── Проверка невалидного суффикса: 123abc ────────────────────
        if (!this.isAtEnd() && this.isIdentStart(this.peek())) {
            // Собираем весь суффикс для информативного сообщения
            let suffix = '';
            while (!this.isAtEnd() && this.isIdentPart(this.peek())) {
                suffix += this.advance();
            }
            this.errors.addError(
                this.file,
                this.startLine,
                `invalid suffix '${suffix}' on numeric literal`,
            );
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Идентификаторы и ключевые слова
    // ═════════════════════════════════════════════════════════════════════

    /**
     * Предусловие: `this.isIdentStart(this.peek())`.
     *
     * Сканирует последовательность из букв (включая Unicode), цифр и
     * символов подчёркивания.  Результат сверяется с таблицей ключевых
     * слов (`KEYWORDS`); при совпадении порождается соответствующий
     * ключевой токен, иначе — `IDENTIFIER`.
     */
    private scanIdentifier(): void {
        let name = '';

        while (!this.isAtEnd() && this.isIdentPart(this.peek())) {
            name += this.advance();
        }

        const kwType = KEYWORDS[name];
        if (kwType !== undefined) {
            this.emit(kwType, name);
        } else {
            this.emit(TokenType.IDENTIFIER, name);
        }
    }

    // ═════════════════════════════════════════════════════════════════════
    //  Классификация символов
    // ═════════════════════════════════════════════════════════════════════

    /** Является ли символ десятичной цифрой? */
    private isDigit(ch: string): boolean {
        return ch >= '0' && ch <= '9';
    }

    /**
     * Может ли символ начинать идентификатор?
     *
     * Допускаются:
     *   • латинские буквы  a-z  A-Z
     *   • символ подчёркивания  _
     *   • любая Unicode-буква (кириллица, греческие и т. д.)
     */
    private isIdentStart(ch: string): boolean {
        if (ch === '_') return true;
        if (ch >= 'a' && ch <= 'z') return true;
        if (ch >= 'A' && ch <= 'Z') return true;

        // Для символов за пределами ASCII проверяем Unicode-категорию
        // «Letter» с помощью свойства \p{L}.
        const code = ch.charCodeAt(0);
        if (code > 127) {
            return /^\p{L}$/u.test(ch);
        }

        return false;
    }

    /**
     * Может ли символ продолжать идентификатор?
     * Те же правила, что и для начала, плюс цифры.
     */
    private isIdentPart(ch: string): boolean {
        return this.isIdentStart(ch) || this.isDigit(ch);
    }
}