// =============================================================================
// highlighter.ts — подсветка синтаксиса Idyllium
// =============================================================================

// ── Категории токенов для подсветки ─────────────────────────────────────────

export type TokenCategory =
    | 'keyword'
    | 'type'
    | 'constant'
    | 'builtin'
    | 'string'
    | 'char'
    | 'number'
    | 'comment'
    | 'operator'
    | 'punctuation'
    | 'identifier'
    | 'plain';

export interface HighlightToken {
    text: string;
    category: TokenCategory;
}

// ── Наборы ключевых слов ────────────────────────────────────────────────────

const KEYWORDS = new Set([
    'if', 'else', 'while', 'do', 'for', 'break', 'continue', 'return',
    'function', 'main', 'use',
    'class', 'extends', 'this', 'constructor', 'destructor',
    'public', 'private',
    'and', 'or', 'xor', 'not',
    'div', 'mod',
]);

const TYPES = new Set([
    'int', 'float', 'string', 'char', 'bool', 'void',
    'array', 'dyn_array',
]);

const CONSTANTS = new Set(['true', 'false']);

const BUILTINS = new Set([
    'to_int', 'to_float', 'to_string',
    'max', 'min', 'sum', 'avg',
]);

// ── Основная функция ────────────────────────────────────────────────────────

/**
 * Токенизирует исходный код для подсветки синтаксиса.
 * Не использует компилятор — упрощённая версия для скорости.
 */
export function tokenize(source: string): HighlightToken[] {
    const tokens: HighlightToken[] = [];
    let pos = 0;

    while (pos < source.length) {
        const ch = source[pos];

        // ── Пробелы ─────────────────────────────────────────────────
        if (/\s/.test(ch)) {
            let text = '';
            while (pos < source.length && /\s/.test(source[pos])) {
                text += source[pos];
                pos++;
            }
            tokens.push({ text, category: 'plain' });
            continue;
        }

        // ── Однострочный комментарий ────────────────────────────────
        if (ch === '/' && source[pos + 1] === '/') {
            let text = '';
            while (pos < source.length && source[pos] !== '\n') {
                text += source[pos];
                pos++;
            }
            tokens.push({ text, category: 'comment' });
            continue;
        }

        // ── Блочный комментарий ─────────────────────────────────────
        if (ch === '/' && source[pos + 1] === '*') {
            let text = '/*';
            pos += 2;
            while (pos < source.length) {
                if (source[pos] === '*' && source[pos + 1] === '/') {
                    text += '*/';
                    pos += 2;
                    break;
                }
                text += source[pos];
                pos++;
            }
            tokens.push({ text, category: 'comment' });
            continue;
        }

        // ── Строка ──────────────────────────────────────────────────
        if (ch === '"') {
            let text = '"';
            pos++;
            while (pos < source.length && source[pos] !== '"') {
                if (source[pos] === '\\' && pos + 1 < source.length) {
                    text += source[pos] + source[pos + 1];
                    pos += 2;
                } else if (source[pos] === '\n') {
                    break; // Незакрытая строка
                } else {
                    text += source[pos];
                    pos++;
                }
            }
            if (pos < source.length && source[pos] === '"') {
                text += '"';
                pos++;
            }
            tokens.push({ text, category: 'string' });
            continue;
        }

        // ── Символ ──────────────────────────────────────────────────
        if (ch === "'") {
            let text = "'";
            pos++;
            while (pos < source.length && source[pos] !== "'") {
                if (source[pos] === '\\' && pos + 1 < source.length) {
                    text += source[pos] + source[pos + 1];
                    pos += 2;
                } else if (source[pos] === '\n') {
                    break;
                } else {
                    text += source[pos];
                    pos++;
                }
            }
            if (pos < source.length && source[pos] === "'") {
                text += "'";
                pos++;
            }
            tokens.push({ text, category: 'char' });
            continue;
        }

        // ── Числа ───────────────────────────────────────────────────
        if (/\d/.test(ch)) {
            let text = '';
            while (pos < source.length && /[\d.]/.test(source[pos])) {
                text += source[pos];
                pos++;
            }
            tokens.push({ text, category: 'number' });
            continue;
        }

        // ── Идентификаторы и ключевые слова ─────────────────────────
        if (/[a-zA-Z_\u00C0-\u024F\u0400-\u04FF]/.test(ch)) {
            let text = '';
            while (pos < source.length && /[a-zA-Z0-9_\u00C0-\u024F\u0400-\u04FF]/.test(source[pos])) {
                text += source[pos];
                pos++;
            }
            let category: TokenCategory = 'identifier';
            if (KEYWORDS.has(text)) category = 'keyword';
            else if (TYPES.has(text)) category = 'type';
            else if (CONSTANTS.has(text)) category = 'constant';
            else if (BUILTINS.has(text)) category = 'builtin';
            tokens.push({ text, category });
            continue;
        }

        // ── Многосимвольные операторы ───────────────────────────────
        const twoChar = source.substring(pos, pos + 2);
        if (['==', '!=', '<=', '>=', '+=', '-=', '*=', '/='].includes(twoChar)) {
            tokens.push({ text: twoChar, category: 'operator' });
            pos += 2;
            continue;
        }

        // ── Односимвольные операторы и пунктуация ───────────────────
        if ('+-*/<>=!'.includes(ch)) {
            tokens.push({ text: ch, category: 'operator' });
            pos++;
            continue;
        }

        if ('{}[]();,.:~'.includes(ch)) {
            tokens.push({ text: ch, category: 'punctuation' });
            pos++;
            continue;
        }

        // ── Всё остальное ───────────────────────────────────────────
        tokens.push({ text: ch, category: 'plain' });
        pos++;
    }

    return tokens;
}

/**
 * Преобразует токены в HTML с подсветкой.
 */
export function highlightToHTML(source: string): string {
    const tokens = tokenize(source);
    let html = '';

    for (const tok of tokens) {
        const escaped = escapeHTML(tok.text);
        if (tok.category === 'plain') {
            html += escaped;
        } else {
            html += `<span class="hl-${tok.category}">${escaped}</span>`;
        }
    }

    return html;
}

function escapeHTML(text: string): string {
    return text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;');
}