// =============================================================================
// ast.ts — Abstract Syntax Tree node definitions for Idyllium
// =============================================================================
//
// Все типы узлов, необходимые для представления ПОЛНОЙ грамматики Idyllium,
// определяются ЗДЕСЬ и СРАЗУ — включая ООП, лямбды, GUI-типы и т.д.
//
// Правило: добавление новой фазы компилятора (парсинг ООП, парсинг лямбд)
// НЕ требует изменений в этом файле — только написания нового кода в парсере
// и генераторе, который создаёт / обрабатывает уже определённые узлы.
//
// Дискриминация узлов — через поле `kind` (TypeScript discriminated unions).
// Все поля помечены `readonly`: AST создаётся парсером один раз и далее
// только читается.  Семантический анализатор хранит аннотации (resolved types,
// symbol info) в отдельных структурах, не модифицируя дерево.
// =============================================================================

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 1 — SOURCE LOCATION
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Координаты в исходном коде.
 * Привязывается к каждому узлу AST для генерации сообщений об ошибках.
 */
export interface SourceLocation {
    readonly file: string;
    readonly line: number;
}

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 2 — TYPE NODES
// ─────────────────────────────────────────────────────────────────────────────
//
// Синтаксическое представление типов в исходном коде.
// Примеры:
//   int                     → PrimitiveType { name: 'int' }
//   array<float, 10>        → ArrayType { elementType: PrimitiveType('float'), size: 10 }
//   dyn_array<string>       → DynArrayType { elementType: PrimitiveType('string') }
//   time.stamp              → QualifiedType { qualifier: 'time', name: 'stamp' }
//   Point2D                 → ClassType { name: 'Point2D' }
//   array<array<int, 6>, 4> → ArrayType { elementType: ArrayType { ... }, size: 4 }
// ─────────────────────────────────────────────────────────────────────────────

/** Примитивный тип: int, float, string, char, bool, void. */
export interface PrimitiveType {
    readonly kind: 'PrimitiveType';
    readonly loc: SourceLocation;
    readonly name: 'int' | 'float' | 'string' | 'char' | 'bool' | 'void';
}

/**
 * Статический массив фиксированной длины.
 * Синтаксис: `array<ElementType, Size>`
 *
 * `size` — всегда целочисленный литерал, определяемый на этапе компиляции.
 * Вложенные массивы (2D и более) поддерживаются естественным образом:
 * `array<array<int, 6>, 4>` → ArrayType внутри ArrayType.
 */
export interface ArrayType {
    readonly kind: 'ArrayType';
    readonly loc: SourceLocation;
    readonly elementType: TypeNode;
    readonly size: number;
}

/**
 * Динамический массив.
 * Синтаксис: `dyn_array<ElementType>`
 */
export interface DynArrayType {
    readonly kind: 'DynArrayType';
    readonly loc: SourceLocation;
    readonly elementType: TypeNode;
}

/**
 * Квалифицированный тип из библиотеки.
 * Синтаксис: `qualifier.name`
 *
 * Примеры:
 *   time.stamp    — метка времени
 *   file.istream  — входной файловый поток
 *   file.ostream  — выходной файловый поток
 *   types.uint8   — 8-битное беззнаковое целое
 *   gui.Window    — окно GUI
 *   gui.Button    — кнопка GUI
 */
export interface QualifiedType {
    readonly kind: 'QualifiedType';
    readonly loc: SourceLocation;
    readonly qualifier: string;
    readonly name: string;
}

/**
 * Тип, определённый пользователем (имя класса).
 * Синтаксис: просто идентификатор, например `Point2D`, `Animal`, `Cat`.
 *
 * Парсер создаёт ClassType, когда идентификатор стоит в позиции типа
 * и не является примитивным типом.  Семантический анализатор проверяет,
 * что класс с таким именем действительно объявлен.
 */
export interface ClassType {
    readonly kind: 'ClassType';
    readonly loc: SourceLocation;
    readonly name: string;
}

/** Любой узел, представляющий тип. */
export type TypeNode =
    | PrimitiveType
    | ArrayType
    | DynArrayType
    | QualifiedType
    | ClassType;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 3 — PROGRAM & IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Корневой узел программы.
 *
 * `main` хранится отдельно от `declarations`, чтобы:
 *   1. Гарантировать на уровне типа, что main() существует.
 *   2. Упростить доступ к точке входа для генератора кода.
 *
 * Парсер отвечает за валидацию наличия ровно одной функции main().
 */
export interface Program {
    readonly kind: 'Program';
    readonly loc: SourceLocation;
    readonly imports: UseDeclaration[];
    readonly declarations: TopLevelDecl[];
    readonly main: FunctionDecl;
}

/**
 * Импорт библиотеки.
 * Синтаксис: `use libraryName;`
 *
 * Имя библиотеки — простой идентификатор без точек.
 * Разрешение (системная vs пользовательская) выполняется позже.
 */
export interface UseDeclaration {
    readonly kind: 'UseDeclaration';
    readonly loc: SourceLocation;
    readonly libraryName: string;
}

/** Объявление верхнего уровня (всё, кроме main и use). */
export type TopLevelDecl = FunctionDecl | ClassDecl;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 4 — PARAMETERS & ARGUMENTS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Параметр функции / метода / конструктора.
 *
 * Пример: `int count = 3`
 *   paramType = PrimitiveType('int')
 *   name = "count"
 *   defaultValue = IntLiteral(3)
 */
export interface Parameter {
    readonly kind: 'Parameter';
    readonly loc: SourceLocation;
    readonly paramType: TypeNode;
    readonly name: string;
    readonly defaultValue: Expression | null;
}

/**
 * Аргумент в вызове функции / метода / конструктора.
 *
 * Позиционный:  `sub(50, 30)`        → name = null
 * Именованный:  `sub(arg1=50)`       → name = "arg1"
 */
export interface Argument {
    readonly loc: SourceLocation;
    readonly name: string | null;
    readonly value: Expression;
}

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 5 — VARIABLE & FUNCTION DECLARATIONS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Объявление переменной.
 * Используется как:
 *   • Инструкция в теле функции:  `int x = 5;`
 *   • Инициализация в for-цикле:  `for (int i = 0; …)`
 *
 * Для переменных классового типа с аргументами конструктора:
 *   `Point2D p(30, 40);`
 *   → initializer = null, constructorArgs = [IntLiteral(30), IntLiteral(40)]
 *
 * Для обычных переменных с инициализатором:
 *   `int x = 5;`
 *   → initializer = IntLiteral(5), constructorArgs = null
 *
 * Без инициализатора (используется дефолтное значение типа):
 *   `int y;`
 *   → initializer = null, constructorArgs = null
 *
 * Множественные объявления `int a, b;` разбиваются парсером
 * на отдельные VariableDecl (по одному на каждое имя).
 */
export interface VariableDecl {
    readonly kind: 'VariableDecl';
    readonly loc: SourceLocation;
    readonly varType: TypeNode;
    readonly name: string;
    readonly initializer: Expression | null;
    readonly constructorArgs: Argument[] | null;
}

/**
 * Объявление функции.
 *
 * Полный синтаксис:
 *   `returnType function name(params) { body }`
 *
 * Особый случай — main():
 *   `main() { body }`                  — без явного типа (подразумевается void)
 *   `void function main() { body }`    — явная форма
 *   `int function main() { body }`     — с возвратом int (допустимо)
 *
 * В AST main() представлен как обычный FunctionDecl с name="main".
 */
export interface FunctionDecl {
    readonly kind: 'FunctionDecl';
    readonly loc: SourceLocation;
    readonly returnType: TypeNode;
    readonly name: string;
    readonly params: Parameter[];
    readonly body: Block;
}

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 6 — CLASS DECLARATIONS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Объявление класса.
 *
 * Синтаксис:
 *   `class Name { members }`
 *   `class Name extends Parent { members }`
 *
 * Точка с запятой после `}` — необязательна.
 *
 * Модификаторы доступа:
 *   По умолчанию все члены — `public`.
 *   Метки `public:` / `private:` переключают доступ для последующих членов
 *   (C++-стиль).  Парсер преобразует метки в конкретные значения `access`
 *   на каждом члене — в AST меток нет, только результат.
 */
export interface ClassDecl {
    readonly kind: 'ClassDecl';
    readonly loc: SourceLocation;
    readonly name: string;
    readonly parentClass: string | null;
    readonly members: ClassMember[];
}

/**
 * Поле класса.
 *
 * Пример:
 *   `int xPos;`
 *   `string name = "default";`
 *
 * Множественные объявления `int xPos, yPos;` разбиваются
 * парсером на отдельные ClassField.
 */
export interface ClassField {
    readonly kind: 'ClassField';
    readonly loc: SourceLocation;
    readonly access: AccessModifier;
    readonly fieldType: TypeNode;
    readonly name: string;
    readonly initializer: Expression | null;
}

/**
 * Метод класса.
 *
 * Синтаксис:
 *   `void function info() { … }`
 *   `float function distance_to(Point2D arg) { … }`
 *
 * Ключевое слово `this` доступно в теле метода без явного объявления
 * в списке параметров (в отличие от Python `self`).
 */
export interface ClassMethod {
    readonly kind: 'ClassMethod';
    readonly loc: SourceLocation;
    readonly access: AccessModifier;
    readonly returnType: TypeNode;
    readonly name: string;
    readonly params: Parameter[];
    readonly body: Block;
}

/**
 * Конструктор класса.
 *
 * Синтаксис:
 *   `constructor ClassName() { … }`
 *   `constructor ClassName(int x, int y) { … }`
 *
 * Допускается несколько конструкторов с разными сигнатурами
 * (перегрузка по количеству/типам параметров).
 */
export interface ClassConstructor {
    readonly kind: 'ClassConstructor';
    readonly loc: SourceLocation;
    readonly access: AccessModifier;
    readonly className: string;
    readonly params: Parameter[];
    readonly body: Block;
}

/**
 * Деструктор класса.
 *
 * Синтаксис:
 *   `destructor ~ClassName() { … }`
 *
 * Не более одного деструктора на класс.  Параметры не допускаются.
 */
export interface ClassDestructor {
    readonly kind: 'ClassDestructor';
    readonly loc: SourceLocation;
    readonly access: AccessModifier;
    readonly className: string;
    readonly body: Block;
}

/** Модификатор доступа к членам класса. */
export type AccessModifier = 'public' | 'private';

/** Любой член класса. */
export type ClassMember =
    | ClassField
    | ClassMethod
    | ClassConstructor
    | ClassDestructor;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 7 — STATEMENTS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Блок — последовательность инструкций в фигурных скобках.
 *
 * Каждый блок образует новую область видимости:
 *   global → function → block → nested block → …
 *   global → class → method → block → …
 */
export interface Block {
    readonly kind: 'Block';
    readonly loc: SourceLocation;
    readonly statements: Statement[];
}

/**
 * Инструкция-выражение.
 *
 * Оборачивает выражение, используемое ради побочного эффекта:
 *   `console.write("hello");`  → ExpressionStmt { expression: MethodCall(…) }
 *   `draw_line(10);`           → ExpressionStmt { expression: FunctionCall(…) }
 */
export interface ExpressionStmt {
    readonly kind: 'ExpressionStmt';
    readonly loc: SourceLocation;
    readonly expression: Expression;
}

/**
 * Допустимые операторы присваивания.
 *
 * Составные операторы (`+=`, `-=`, `*=`, `/=`) — синтаксический сахар:
 *   `a += b` эквивалентно `a = a + b`
 * но хранятся в AST «как есть» для точности сообщений об ошибках.
 */
export type AssignmentOperator = '=' | '+=' | '-=' | '*=' | '/=';

/**
 * Инструкция присваивания.
 *
 * Присваивание — ИНСТРУКЦИЯ, а не выражение.
 * Это намеренное ограничение Idyllium, предотвращающее ошибки вида
 * `if (x = 5)` — компилятор сообщит: "did you mean '=='?".
 *
 * Допустимые цели присваивания (левая сторона):
 *   • Идентификатор:      `money = 25000;`
 *   • Индексный доступ:   `P[0] = 72;`
 *   • Доступ к свойству:  `label.text = "hello";`
 */
export interface AssignmentStmt {
    readonly kind: 'AssignmentStmt';
    readonly loc: SourceLocation;
    readonly target: AssignmentTarget;
    readonly operator: AssignmentOperator;
    readonly value: Expression;
}

/** Допустимые выражения в левой части присваивания. */
export type AssignmentTarget =
    | IdentifierExpr
    | IndexAccessExpr
    | PropertyAccessExpr;

/**
 * Условный оператор.
 *
 * Синтаксис:
 *   `if (condition) { … }`
 *   `if (condition) { … } else { … }`
 *   `if (condition) { … } else if (condition) { … } else { … }`
 *
 * Цепочки `else if` хранятся плоским списком в `elseIfClauses`,
 * а не вложенным IfStmt в elseBlock — это упрощает генерацию кода
 * и делает сообщения об ошибках точнее.
 *
 * Условие ОБЯЗАНО иметь тип `bool`.  Семантический анализатор
 * отклоняет числа, строки и любые другие типы в условии.
 */
export interface IfStmt {
    readonly kind: 'IfStmt';
    readonly loc: SourceLocation;
    readonly condition: Expression;
    readonly thenBlock: Block;
    readonly elseIfClauses: ElseIfClause[];
    readonly elseBlock: Block | null;
}

/** Одна ветка `else if`. */
export interface ElseIfClause {
    readonly loc: SourceLocation;
    readonly condition: Expression;
    readonly block: Block;
}

/**
 * Цикл `while`.
 *
 * Синтаксис: `while (condition) { body }`
 *
 * Условие проверяется ПЕРЕД каждой итерацией.
 */
export interface WhileStmt {
    readonly kind: 'WhileStmt';
    readonly loc: SourceLocation;
    readonly condition: Expression;
    readonly body: Block;
}

/**
 * Цикл `do-while`.
 *
 * Синтаксис: `do { body } while (condition);`
 *
 * Тело выполняется хотя бы один раз; условие проверяется ПОСЛЕ каждой
 * итерации.
 */
export interface DoWhileStmt {
    readonly kind: 'DoWhileStmt';
    readonly loc: SourceLocation;
    readonly body: Block;
    readonly condition: Expression;
}

/**
 * Цикл `for`.
 *
 * Синтаксис: `for (init; condition; update) { body }`
 *
 * Ограничения Idyllium:
 *   • init — всегда объявление переменной (`int i = 0`)
 *   • update — всегда присваивание (`i = i + 1` или `i += 1`)
 *   • переменная из init видна только внутри цикла
 */
export interface ForStmt {
    readonly kind: 'ForStmt';
    readonly loc: SourceLocation;
    readonly init: VariableDecl;
    readonly condition: Expression;
    readonly update: AssignmentStmt;
    readonly body: Block;
}

/**
 * Возврат из функции.
 *
 * Синтаксис:
 *   `return expr;`   — для функций с возвращаемым типом
 *   `return;`        — для void-функций
 */
export interface ReturnStmt {
    readonly kind: 'ReturnStmt';
    readonly loc: SourceLocation;
    readonly value: Expression | null;
}

/** Досрочный выход из цикла. */
export interface BreakStmt {
    readonly kind: 'BreakStmt';
    readonly loc: SourceLocation;
}

/** Пропуск текущей итерации цикла. */
export interface ContinueStmt {
    readonly kind: 'ContinueStmt';
    readonly loc: SourceLocation;
}

/** Любая инструкция внутри блока. */
export type Statement =
    | VariableDecl
    | AssignmentStmt
    | ExpressionStmt
    | IfStmt
    | WhileStmt
    | DoWhileStmt
    | ForStmt
    | ReturnStmt
    | BreakStmt
    | ContinueStmt;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 8 — EXPRESSIONS
// ─────────────────────────────────────────────────────────────────────────────

// ── Литералы ────────────────────────────────────────────────────────────────

/** Целочисленный литерал: `42`, `0`, `255`. */
export interface IntLiteralExpr {
    readonly kind: 'IntLiteral';
    readonly loc: SourceLocation;
    readonly value: number;
}

/** Дробный литерал: `3.14`, `0.5`. */
export interface FloatLiteralExpr {
    readonly kind: 'FloatLiteral';
    readonly loc: SourceLocation;
    readonly value: number;
}

/**
 * Строковый литерал: `"hello"`.
 *
 * `value` содержит раскрытые escape-последовательности
 * (раскрытие выполняется лексером).
 */
export interface StringLiteralExpr {
    readonly kind: 'StringLiteral';
    readonly loc: SourceLocation;
    readonly value: string;
}

/**
 * Символьный литерал: `'A'`, `'\n'`.
 *
 * `value` — один символ (escape уже раскрыт лексером).
 */
export interface CharLiteralExpr {
    readonly kind: 'CharLiteral';
    readonly loc: SourceLocation;
    readonly value: string;
}

/** Логический литерал: `true` или `false`. */
export interface BoolLiteralExpr {
    readonly kind: 'BoolLiteral';
    readonly loc: SourceLocation;
    readonly value: boolean;
}

/**
 * Литерал массива: `[1, 2, 3]`, `["a", "b"]`.
 *
 * Используется для инициализации `array<T, N>` и `dyn_array<T>`.
 * Тип и размер проверяются семантическим анализатором.
 */
export interface ArrayLiteralExpr {
    readonly kind: 'ArrayLiteral';
    readonly loc: SourceLocation;
    readonly elements: Expression[];
}

// ── Идентификаторы и this ───────────────────────────────────────────────────

/**
 * Идентификатор (имя переменной, функции, класса).
 *
 * Примеры: `money`, `counter`, `my_func`
 *
 * Также используется как цель присваивания (AssignmentTarget).
 */
export interface IdentifierExpr {
    readonly kind: 'Identifier';
    readonly loc: SourceLocation;
    readonly name: string;
}

/**
 * Ключевое слово `this` — ссылка на текущий объект в методе класса.
 *
 * Пример: `this.xPos`, `this.info()`
 */
export interface ThisExpr {
    readonly kind: 'ThisExpr';
    readonly loc: SourceLocation;
}

// ── Операции ────────────────────────────────────────────────────────────────

/**
 * Допустимые бинарные операторы.
 *
 * Арифметические:  +  -  *  /
 * Сравнения:       ==  !=  <  >  <=  >=
 * Логические:      and  or  xor
 *
 * Приоритеты (от низшего к высшему):
 *   1. or, xor
 *   2. and
 *   3. ==, !=
 *   4. <, >, <=, >=
 *   5. +, -
 *   6. *, /
 *
 * Оператор `/` ВСЕГДА возвращает float (ключевая особенность Idyllium).
 */
export type BinaryOperator =
    | '+' | '-' | '*' | '/'
    | '==' | '!=' | '<' | '>' | '<=' | '>='
    | 'and' | 'or' | 'xor';

/** Бинарная операция: `left operator right`. */
export interface BinaryExpr {
    readonly kind: 'BinaryExpr';
    readonly loc: SourceLocation;
    readonly operator: BinaryOperator;
    readonly left: Expression;
    readonly right: Expression;
}

/**
 * Унарный минус: `-expression`.
 *
 * Пример: `-A`, `-(x + y)`
 *
 * Примечание: `-42` в исходном коде представляется как
 * UnaryMinus(IntLiteral(42)), а не как IntLiteral(-42).
 * Оптимизация свёртки констант — задача более поздних фаз.
 */
export interface UnaryMinusExpr {
    readonly kind: 'UnaryMinus';
    readonly loc: SourceLocation;
    readonly operand: Expression;
}

/**
 * Логическая инверсия: `not(expression)`.
 *
 * В Idyllium `not` — функцеподобный синтаксис с обязательными скобками:
 *   `not(A)`, `not(x > 5)`
 *
 * Это НЕ обычный вызов функции — это языковая конструкция.
 * Аргумент обязан иметь тип bool.
 */
export interface NotExpr {
    readonly kind: 'NotExpr';
    readonly loc: SourceLocation;
    readonly argument: Expression;
}

// ── Вызовы и доступ ─────────────────────────────────────────────────────────

/**
 * Вызов функции (без объекта-получателя).
 *
 * Покрывает:
 *   • Пользовательские функции:  `my_func(1, 2)`
 *   • Встроенные функции:        `div(a, b)`, `mod(a, b)`,
 *                                 `to_int(x)`, `to_string(x)`,
 *                                 `max(arr)`, `sum(arr)`, `avg(arr)`
 *
 * Ключевые слова `div` и `mod` обрабатываются парсером особо:
 * при виде `KW_DIV (` парсер создаёт FunctionCall с callee = "div".
 * Семантический анализатор распознаёт их как встроенные.
 */
export interface FunctionCallExpr {
    readonly kind: 'FunctionCall';
    readonly loc: SourceLocation;
    readonly callee: string;
    readonly args: Argument[];
}

/**
 * Вызов метода на объекте: `object.method(args)`.
 *
 * Покрывает:
 *   • Методы массивов/строк: `arr.add(5)`, `str.find('x')`
 *   • Методы экземпляров:     `p1.info()`, `p1.distance_to(p2)`
 *   • Вызовы из библиотек:    `console.write("hello")`,
 *                              `math.abs(-5)`,
 *                              `random.create_int(1, 6)`
 *
 * Парсер НЕ различает библиотечные вызовы и вызовы методов —
 * это делает семантический анализатор, проверяя, является ли
 * `object` именем библиотеки или переменной.
 */
export interface MethodCallExpr {
    readonly kind: 'MethodCall';
    readonly loc: SourceLocation;
    readonly object: Expression;
    readonly method: string;
    readonly args: Argument[];
}

/**
 * Доступ к свойству объекта: `object.property`.
 *
 * Покрывает:
 *   • Поля экземпляров:     `p1.xPos`, `label.text`
 *   • Константы библиотек:  `math.pi`, `math.e`
 *
 * Также используется как цель присваивания (AssignmentTarget):
 *   `label.text = "hello";`
 */
export interface PropertyAccessExpr {
    readonly kind: 'PropertyAccess';
    readonly loc: SourceLocation;
    readonly object: Expression;
    readonly property: string;
}

/**
 * Индексный доступ: `object[index]`.
 *
 * Покрывает:
 *   • Элементы массива: `arr[0]`, `nums[i]`
 *   • Символы строки:   `str[3]`
 *   • Элементы 2D-массива: `mx[row][col]` → вложенные IndexAccess
 *
 * Также используется как цель присваивания (AssignmentTarget):
 *   `arr[0] = 42;`
 *
 * Проверка границ выполняется в рантайме.
 */
export interface IndexAccessExpr {
    readonly kind: 'IndexAccess';
    readonly loc: SourceLocation;
    readonly object: Expression;
    readonly index: Expression;
}

// ── Лямбда ──────────────────────────────────────────────────────────────────

/**
 * Лямбда-выражение (анонимная функция).
 *
 * Синтаксис:
 *   `returnType function(params) { body }`
 *
 * Пример:
 *   ```
 *   btn.on_click = void function() {
 *       label.text = "Clicked!";
 *   }
 *   ```
 *
 * Захват переменных — по ссылке: лямбда видит переменные из области
 * видимости, в которой она создана, и изменения внутри лямбды
 * отражаются на оригинальных переменных.
 */
export interface LambdaExpr {
    readonly kind: 'Lambda';
    readonly loc: SourceLocation;
    readonly returnType: TypeNode;
    readonly params: Parameter[];
    readonly body: Block;
}

// ── Объединённый тип выражений ──────────────────────────────────────────────

/** Любое выражение. */
export type Expression =
    | IntLiteralExpr
    | FloatLiteralExpr
    | StringLiteralExpr
    | CharLiteralExpr
    | BoolLiteralExpr
    | ArrayLiteralExpr
    | IdentifierExpr
    | ThisExpr
    | BinaryExpr
    | UnaryMinusExpr
    | NotExpr
    | FunctionCallExpr
    | MethodCallExpr
    | PropertyAccessExpr
    | IndexAccessExpr
    | LambdaExpr;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 9 — UNION TYPE: ALL AST NODES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Объединённый тип ВСЕХ узлов AST.
 * Полезен для обобщённых visitor-функций и утилит обхода дерева.
 */
export type AnyNode =
    // Types
    | PrimitiveType
    | ArrayType
    | DynArrayType
    | QualifiedType
    | ClassType
    // Top-level
    | Program
    | UseDeclaration
    // Declarations
    | VariableDecl
    | FunctionDecl
    | Parameter
    // Class
    | ClassDecl
    | ClassField
    | ClassMethod
    | ClassConstructor
    | ClassDestructor
    // Statements
    | Block
    | ExpressionStmt
    | AssignmentStmt
    | IfStmt
    | WhileStmt
    | DoWhileStmt
    | ForStmt
    | ReturnStmt
    | BreakStmt
    | ContinueStmt
    // Expressions
    | IntLiteralExpr
    | FloatLiteralExpr
    | StringLiteralExpr
    | CharLiteralExpr
    | BoolLiteralExpr
    | ArrayLiteralExpr
    | IdentifierExpr
    | ThisExpr
    | BinaryExpr
    | UnaryMinusExpr
    | NotExpr
    | FunctionCallExpr
    | MethodCallExpr
    | PropertyAccessExpr
    | IndexAccessExpr
    | LambdaExpr;

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 10 — KIND CONSTANTS & TYPE GUARDS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Множество `kind`-значений, соответствующих выражениям.
 * Используется для быстрой проверки «является ли узел выражением?»
 * без перечисления всех вариантов.
 */
const EXPRESSION_KINDS: ReadonlySet<string> = new Set([
    'IntLiteral',
    'FloatLiteral',
    'StringLiteral',
    'CharLiteral',
    'BoolLiteral',
    'ArrayLiteral',
    'Identifier',
    'ThisExpr',
    'BinaryExpr',
    'UnaryMinus',
    'NotExpr',
    'FunctionCall',
    'MethodCall',
    'PropertyAccess',
    'IndexAccess',
    'Lambda',
]);

/** Множество `kind`-значений, соответствующих инструкциям. */
const STATEMENT_KINDS: ReadonlySet<string> = new Set([
    'VariableDecl',
    'AssignmentStmt',
    'ExpressionStmt',
    'IfStmt',
    'WhileStmt',
    'DoWhileStmt',
    'ForStmt',
    'ReturnStmt',
    'BreakStmt',
    'ContinueStmt',
]);

/** Проверяет, является ли узел выражением. */
export function isExpression(node: { kind: string }): node is Expression {
    return EXPRESSION_KINDS.has(node.kind);
}

/** Проверяет, является ли узел инструкцией. */
export function isStatement(node: { kind: string }): node is Statement {
    return STATEMENT_KINDS.has(node.kind);
}

/** Проверяет, является ли выражение допустимой целью присваивания. */
export function isAssignmentTarget(node: Expression): node is AssignmentTarget {
    return node.kind === 'Identifier'
        || node.kind === 'IndexAccess'
        || node.kind === 'PropertyAccess';
}

/**
 * Проверяет, является ли тип примитивным.
 * Полезно для быстрых проверок без switch/case.
 */
export function isPrimitiveType(t: TypeNode): t is PrimitiveType {
    return t.kind === 'PrimitiveType';
}

/** Проверяет, является ли тип числовым (int или float). */
export function isNumericPrimitiveType(t: TypeNode): boolean {
    return t.kind === 'PrimitiveType'
        && (t.name === 'int' || t.name === 'float');
}

// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 11 — HELPERS FOR CREATING LOCATIONS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Создаёт SourceLocation из файла и номера строки.
 *
 * Используется парсером при построении узлов:
 *   `loc(this.currentToken)`
 */
export function loc(file: string, line: number): SourceLocation {
    return { file, line };
}