// =============================================================================
// index.ts — точка входа: полный пайплайн компиляции и исполнения Idyllium
// =============================================================================
//
// Соединяет все модули компилятора в единый поток:
//
//   Исходный код (.idyl)
//       ↓  Lexer
//   Массив токенов
//       ↓  Parser
//   AST (абстрактное синтаксическое дерево)
//       ↓  Analyzer
//   Аннотированный AST + SemanticInfo
//       ↓  CodeGenerator
//   JavaScript-код (строка)
//       ↓  Runtime + Executor
//   Результат выполнения
//
// Экспортирует:
//   • compileIdyllium()  — компиляция до JS-строки (без исполнения)
//   • runIdyllium()      — компиляция + исполнение
//   • CompileResult      — результат компиляции
//   • RunResult          — результат исполнения
//   • Все необходимые типы для IDE
// =============================================================================

import { Lexer }                                from './compiler/lexer';
import { Parser }                               from './compiler/parser';
import { Analyzer, SemanticInfo }               from './compiler/analyzer';
import { CodeGenerator }                        from './compiler/codegen';
import { ErrorCollector, CompileError }         from './compiler/errors';
import { Program }                              from './compiler/ast';
import { Token }                                from './compiler/tokens';
import {
    createRuntime,
    IdylRuntime,
    ConsoleIO,
    RuntimeOptions,
    VirtualFS,
    InMemoryFS,
    IdylRuntimeError,
} from './runtime/runtime';


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 1 — RESULT TYPES
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Результат компиляции (без исполнения).
 */
export interface CompileResult {
    /** Компиляция прошла без ошибок? */
    readonly success: boolean;

    /** Сгенерированный JS-код (null если были ошибки). */
    readonly jsCode: string | null;

    /** Все ошибки компиляции. */
    readonly errors: CompileError[];

    /** Все предупреждения компиляции. */
    readonly warnings: CompileError[];

    /** Отформатированное сообщение обо всех ошибках и предупреждениях. */
    readonly diagnostics: string;

    /** Массив токенов (для отладки / подсветки). */
    readonly tokens: Token[];

    /** AST (для отладки / визуализации). */
    readonly ast: Program | null;

    /** Семантическая информация (для отладки). */
    readonly semanticInfo: SemanticInfo | null;
}

/**
 * Результат исполнения.
 */
export interface RunResult {
    /** Программа завершилась без ошибок? */
    readonly success: boolean;

    /** Ошибка времени выполнения (null если успех). */
    readonly runtimeError: string | null;

    /** Весь текст, выведенный программой в консоль. */
    readonly output: string;

    /** Время исполнения в миллисекундах. */
    readonly executionTimeMs: number;

    /** Результат компиляции (вложен для доступа к диагностикам). */
    readonly compilation: CompileResult;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 2 — COMPILE
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Компилирует исходный код Idyllium в JavaScript.
 *
 * Не выполняет код — только проверяет и генерирует JS-строку.
 *
 * @param source  Полный текст программы.
 * @param file    Имя файла (для сообщений об ошибках).
 * @returns       Результат компиляции.
 *
 * @example
 * ```typescript
 * const result = compileIdyllium(`
 *     use console;
 *     main() {
 *         console.write("Hello, World!", '\\n');
 *     }
 * `, 'main.idyl');
 *
 * if (result.success) {
 *     console.log(result.jsCode);
 * } else {
 *     console.error(result.diagnostics);
 * }
 * ```
 */
export function compileIdyllium(source: string, file: string = 'main.idyl'): CompileResult {
    const errors = new ErrorCollector(100);
    let tokens: Token[] = [];
    let ast: Program | null = null;
    let semanticInfo: SemanticInfo | null = null;
    let jsCode: string | null = null;

    // ── Фаза 1: Лексический анализ ──────────────────────────────────
    const lexer = new Lexer(source, file, errors);
    tokens = lexer.tokenize();

    // Если лексер обнаружил критические ошибки, парсер может сломаться,
    // но мы всё равно пробуем — для сбора максимума диагностик.

    // ── Фаза 2: Синтаксический анализ ───────────────────────────────
    if (!errors.isOverflow()) {
        const parser = new Parser(tokens, file, errors);
        ast = parser.parse();
    }

    // ── Фаза 3: Семантический анализ ────────────────────────────────
    if (ast !== null && !errors.isOverflow()) {
        const analyzer = new Analyzer(file, errors);
        semanticInfo = analyzer.analyze(ast);
    }

    // ── Фаза 4: Генерация кода ──────────────────────────────────────
    if (ast !== null && semanticInfo !== null && !errors.hasErrors()) {
        const codegen = new CodeGenerator(semanticInfo);
        jsCode = codegen.generate(ast);
    }

    return {
        success: !errors.hasErrors(),
        jsCode,
        errors: errors.getErrors(),
        warnings: errors.getWarnings(),
        diagnostics: errors.format(),
        tokens,
        ast,
        semanticInfo,
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 3 — RUN
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Компилирует и исполняет программу Idyllium.
 *
 * @param source   Полный текст программы.
 * @param options  Параметры исполнения (консоль, файловая система).
 * @param file     Имя файла (для сообщений).
 * @returns        Результат исполнения.
 *
 * @example
 * ```typescript
 * // Простейший запуск с буферизацией вывода
 * const result = await runIdyllium(`
 *     use console;
 *     main() {
 *         console.write("Hello!\\n");
 *     }
 * `);
 * console.log(result.output); // "Hello!\n"
 * ```
 *
 * @example
 * ```typescript
 * // Запуск с кастомным вводом-выводом (для IDE)
 * const result = await runIdyllium(source, {
 *     console: {
 *         print: (text) => terminalDiv.textContent += text,
 *         readLine: () => showInputPrompt(),
 *     },
 *     fs: myVirtualFS,
 * });
 * ```
 */
export async function runIdyllium(
    source: string,
    options?: Partial<RuntimeOptions>,
    file: string = 'main.idyl',
): Promise<RunResult> {

    // ── Компиляция ──────────────────────────────────────────────────
    const compilation = compileIdyllium(source, file);

    if (!compilation.success || compilation.jsCode === null) {
        return {
            success: false,
            runtimeError: null,
            output: '',
            executionTimeMs: 0,
            compilation,
        };
    }

    // ── Подготовка рантайма ──────────────────────────────────────────
    let outputBuffer = '';

    const defaultConsoleIO: ConsoleIO = {
        print(text: string): void {
            outputBuffer += text;
        },
        readLine(): Promise<string> {
            // В режиме без интерактивного ввода — возвращаем пустую строку.
            // IDE должна предоставить свою реализацию.
            return Promise.resolve('');
        },
    };

    const consoleIO = options?.console ?? defaultConsoleIO;

    // Если используется кастомный print — всё равно буферизуем для output
    const wrappedConsoleIO: ConsoleIO = {
        print(text: string): void {
            outputBuffer += text;
            consoleIO.print(text);
        },
        readLine(): Promise<string> {
            return consoleIO.readLine();
        },
    };

    // Если пользователь не передал свой console, не дублируем вывод
    const finalConsoleIO = options?.console
        ? wrappedConsoleIO
        : defaultConsoleIO;

    const runtime = createRuntime({
        console: finalConsoleIO,
        fs: options?.fs,
    });

    // ── Исполнение ──────────────────────────────────────────────────
    const startTime = performance.now();
    let runtimeError: string | null = null;

    try {
        // Сгенерированный код — IIFE, возвращающая функцию:
        //   (async function($rt) { ... })
        // Нам нужно вызвать её, передав $rt.

        // Создаём функцию из строки.
        // Используем AsyncFunction для поддержки await внутри.
        const AsyncFunction = Object.getPrototypeOf(
            async function () {}
        ).constructor;

        const executor = new AsyncFunction('$rt', `
            const __fn = ${compilation.jsCode};
            return __fn($rt);
        `);

        await executor(runtime);

    } catch (err: unknown) {
        if (err instanceof IdylRuntimeError) {
            runtimeError = err.message;
        } else if (err instanceof Error) {
            runtimeError = `internal error: ${err.message}`;
        } else {
            runtimeError = `unknown error: ${String(err)}`;
        }
    }

    const executionTimeMs = performance.now() - startTime;

    return {
        success: runtimeError === null,
        runtimeError,
        output: outputBuffer,
        executionTimeMs,
        compilation,
    };
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 4 — CONVENIENCE HELPERS
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Быстрый запуск программы с буферизацией вывода.
 * Удобно для тестирования из Node.js / console.
 *
 * @example
 * ```typescript
 * const output = await quickRun(`
 *     use console;
 *     main() {
 *         console.write("2 + 2 = ", 2 + 2, '\\n');
 *     }
 * `);
 * console.log(output); // "2 + 2 = 4\n"
 * ```
 */
export async function quickRun(source: string, file?: string): Promise<string> {
    const result = await runIdyllium(source, undefined, file);

    if (!result.compilation.success) {
        throw new Error(
            `Compilation failed:\n${result.compilation.diagnostics}`
        );
    }

    if (!result.success) {
        throw new Error(result.runtimeError ?? 'Unknown runtime error');
    }

    return result.output;
}


/**
 * Создаёт «сессию» — предконфигурированное окружение для многократного
 * запуска программ с одним и тем же IO / файловой системой.
 *
 * Полезно для IDE: создаётся один раз при открытии страницы,
 * переиспользуется при каждом нажатии "Запустить".
 *
 * @example
 * ```typescript
 * const session = createSession({
 *     console: {
 *         print: (text) => terminal.append(text),
 *         readLine: () => inputPrompt(),
 *     },
 * });
 *
 * // При нажатии кнопки "Запустить":
 * const result = await session.run(editorContent);
 * ```
 */
export interface IdylSession {
    /** Компилирует без исполнения. */
    compile(source: string, file?: string): CompileResult;

    /** Компилирует и исполняет. */
    run(source: string, file?: string): Promise<RunResult>;

    /** Виртуальная файловая система (для предзагрузки файлов). */
    readonly fs: VirtualFS;
}

export function createSession(options: Partial<RuntimeOptions> = {}): IdylSession {
    const fs = options.fs ?? new InMemoryFS();

    return {
        compile(source: string, file: string = 'main.idyl'): CompileResult {
            return compileIdyllium(source, file);
        },

        async run(source: string, file: string = 'main.idyl'): Promise<RunResult> {
            return runIdyllium(source, { ...options, fs }, file);
        },

        fs,
    };
}


