// =============================================================================
// parser.ts — синтаксический анализатор языка Idyllium
// =============================================================================
//
// Превращает плоский массив токенов (из лексера) в AST (ast.ts).
//
// Архитектура:
//   • Рекурсивный спуск (recursive descent) — по одному методу на каждое
//     правило грамматики.
//   • Приоритетный разбор выражений по методу Пратта (Pratt parsing /
//     precedence climbing) — элегантно обрабатывает бинарные операторы
//     любой вложенности без дублирования кода.
//   • Error recovery — при встрече синтаксической ошибки парсер
//     регистрирует её в ErrorCollector и пытается «синхронизироваться»
//     (пропустить токены до следующей точки с запятой или закрывающей
//     скобки), чтобы найти следующие ошибки за один проход.
//
// Порядок разбора верхнего уровня:
//   Program = { UseDeclaration } { FunctionDecl | ClassDecl } MainDecl
//
// Ограничения:
//   • `main()` обязательна и ровно одна на программу
//   • `use` допускается только в начале файла (до любых объявлений)
//   • Вложенные функции — только лямбды (анонимные), не именованные
// =============================================================================

import {
    Token, TokenType, KEYWORDS,
    tokenTypeName, tokenDisplayValue,
} from './tokens';

import { ErrorCollector } from './errors';

import {
    // Source location
    SourceLocation, loc,

    // Type nodes
    TypeNode, PrimitiveType, ArrayType, DynArrayType,
    QualifiedType, ClassType,

    // Program & imports
    Program, UseDeclaration, TopLevelDecl,

    // Parameters & arguments
    Parameter, Argument,

    // Declarations
    VariableDecl, FunctionDecl,

    // Class
    ClassDecl, ClassMember, ClassField, ClassMethod,
    ClassConstructor, ClassDestructor, AccessModifier,

    // Statements
    Block, Statement, ExpressionStmt, AssignmentStmt,
    AssignmentOperator, AssignmentTarget,
    IfStmt, ElseIfClause, WhileStmt, DoWhileStmt, ForStmt,
    ReturnStmt, BreakStmt, ContinueStmt,

    // Expressions
    Expression, BinaryOperator, BinaryExpr,
    IntLiteralExpr, FloatLiteralExpr, StringLiteralExpr,
    CharLiteralExpr, BoolLiteralExpr, ArrayLiteralExpr,
    IdentifierExpr, ThisExpr,
    UnaryMinusExpr, NotExpr,
    FunctionCallExpr, MethodCallExpr,
    PropertyAccessExpr, IndexAccessExpr,
    LambdaExpr,

    // Guards
    isAssignmentTarget,
} from './ast';


// ─────────────────────────────────────────────────────────────────────────────
//  Приоритеты бинарных операторов (Pratt parsing)
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Числовые приоритеты для бинарных операторов.
 * Бо́льшее число = бо́льший приоритет (связывает сильнее).
 *
 * Уровни:
 *   10  or, xor         (самый слабый бинарный)
 *   20  and
 *   30  ==, !=
 *   40  <, >, <=, >=
 *   50  +, -
 *   60  *, /             (самый сильный бинарный)
 *
 * Унарный минус и not() обрабатываются в parseUnary(), а не здесь.
 */
function getBinaryPrecedence(type: TokenType): number {
    switch (type) {
        case TokenType.KW_OR:
        case TokenType.KW_XOR:
            return 10;
        case TokenType.KW_AND:
            return 20;
        case TokenType.EQ:
        case TokenType.NEQ:
            return 30;
        case TokenType.LT:
        case TokenType.GT:
        case TokenType.LTE:
        case TokenType.GTE:
            return 40;
        case TokenType.PLUS:
        case TokenType.MINUS:
            return 50;
        case TokenType.STAR:
        case TokenType.SLASH:
            return 60;
        default:
            return -1; // не является бинарным оператором
    }
}

/**
 * Преобразует тип токена в BinaryOperator (для узла AST).
 * Вызывается только для токенов, прошедших проверку getBinaryPrecedence > 0.
 */
function tokenToBinaryOp(type: TokenType): BinaryOperator {
    switch (type) {
        case TokenType.PLUS:    return '+';
        case TokenType.MINUS:   return '-';
        case TokenType.STAR:    return '*';
        case TokenType.SLASH:   return '/';
        case TokenType.EQ:      return '==';
        case TokenType.NEQ:     return '!=';
        case TokenType.LT:      return '<';
        case TokenType.GT:      return '>';
        case TokenType.LTE:     return '<=';
        case TokenType.GTE:     return '>=';
        case TokenType.KW_AND:  return 'and';
        case TokenType.KW_OR:   return 'or';
        case TokenType.KW_XOR:  return 'xor';
        default:
            throw new Error(`Internal: not a binary operator: ${type}`);
    }
}


// ─────────────────────────────────────────────────────────────────────────────
//  Множество токенов, начинающих тип
// ─────────────────────────────────────────────────────────────────────────────

/** Может ли данный токен начинать объявление типа? */
function isTypeStart(type: TokenType): boolean {
    switch (type) {
        case TokenType.KW_INT:
        case TokenType.KW_FLOAT:
        case TokenType.KW_STRING:
        case TokenType.KW_CHAR:
        case TokenType.KW_BOOL:
        case TokenType.KW_VOID:
        case TokenType.KW_ARRAY:
        case TokenType.KW_DYN_ARRAY:
        case TokenType.IDENTIFIER:
            return true;
        default:
            return false;
    }
}

/** Является ли токен оператором присваивания? */
function isAssignmentOp(type: TokenType): AssignmentOperator | null {
    switch (type) {
        case TokenType.ASSIGN:       return '=';
        case TokenType.PLUS_ASSIGN:  return '+=';
        case TokenType.MINUS_ASSIGN: return '-=';
        case TokenType.STAR_ASSIGN:  return '*=';
        case TokenType.SLASH_ASSIGN: return '/=';
        default:                     return null;
    }
}


// =============================================================================
//  PARSER CLASS
// =============================================================================

export class Parser {

    // ── Неизменяемые параметры ───────────────────────────────────────────
    private readonly tokens: Token[];
    private readonly file: string;
    private readonly errors: ErrorCollector;

    // ── Состояние ───────────────────────────────────────────────────────
    private pos: number = 0;

    constructor(tokens: Token[], file: string, errors: ErrorCollector) {
        this.tokens = tokens;
        this.file = file;
        this.errors = errors;
    }

    // =====================================================================
    //  Навигация по токенам
    // =====================================================================

    /** Текущий токен (или EOF, если конец). */
    private current(): Token {
        return this.tokens[this.pos] ?? this.tokens[this.tokens.length - 1];
    }

    /** Тип текущего токена. */
    private currentType(): TokenType {
        return this.current().type;
    }

    /** Номер строки текущего токена. */
    private currentLine(): number {
        return this.current().line;
    }

    /** Достигнут ли конец потока токенов? */
    private isAtEnd(): boolean {
        return this.currentType() === TokenType.EOF;
    }

    /**
     * Заглядывание вперёд на `offset` токенов.
     * `peek(0)` = текущий, `peek(1)` = следующий, и т.д.
     */
    private peek(offset: number = 0): Token {
        const idx = this.pos + offset;
        return idx < this.tokens.length
            ? this.tokens[idx]
            : this.tokens[this.tokens.length - 1];
    }

    /** Потребляет текущий токен и возвращает его. */
    private advance(): Token {
        const tok = this.current();
        if (!this.isAtEnd()) this.pos++;
        return tok;
    }

    /**
     * Проверяет, что текущий токен имеет указанный тип.
     * Если да — потребляет его и возвращает.
     * Если нет — регистрирует ошибку и возвращает `null`.
     */
    private expect(type: TokenType, contextMsg?: string): Token | null {
        if (this.currentType() === type) {
            return this.advance();
        }
        const where = contextMsg ? ` ${contextMsg}` : '';
        this.errors.addError(
            this.file,
            this.currentLine(),
            `expected ${tokenTypeName(type)} but found ${tokenDisplayValue(this.current())}${where}`,
        );
        return null;
    }

    /**
     * Если текущий токен имеет указанный тип — потребляет его и
     * возвращает `true`.  Иначе — ничего не делает, возвращает `false`.
     */
    private match(type: TokenType): boolean {
        if (this.currentType() === type) {
            this.advance();
            return true;
        }
        return false;
    }

    /** Создаёт SourceLocation для текущей позиции. */
    private here(): SourceLocation {
        return loc(this.file, this.currentLine());
    }

    /** Создаёт SourceLocation из конкретного токена. */
    private locOf(token: Token): SourceLocation {
        return loc(token.file, token.line);
    }

    // =====================================================================
    //  Error recovery
    // =====================================================================

    /**
     * Пропускает токены до одного из «синхронизирующих» — точки с запятой,
     * закрывающей фигурной скобки, или начала нового объявления/инструкции.
     *
     * Вызывается после регистрации ошибки, чтобы парсер мог продолжить
     * разбор остального файла.
     */
    private synchronize(): void {
        while (!this.isAtEnd()) {
            // После точки с запятой — хорошая точка для возобновления.
            if (this.currentType() === TokenType.SEMICOLON) {
                this.advance();
                return;
            }

            // Закрывающая скобка — конец блока, тоже хорошо.
            if (this.currentType() === TokenType.RBRACE) {
                return; // НЕ потребляем — пусть вызывающий код обработает '}'
            }

            // Начало нового объявления / инструкции — остановиться.
            switch (this.currentType()) {
                case TokenType.KW_INT:
                case TokenType.KW_FLOAT:
                case TokenType.KW_STRING:
                case TokenType.KW_CHAR:
                case TokenType.KW_BOOL:
                case TokenType.KW_VOID:
                case TokenType.KW_ARRAY:
                case TokenType.KW_DYN_ARRAY:
                case TokenType.KW_IF:
                case TokenType.KW_WHILE:
                case TokenType.KW_DO:
                case TokenType.KW_FOR:
                case TokenType.KW_RETURN:
                case TokenType.KW_BREAK:
                case TokenType.KW_CONTINUE:
                case TokenType.KW_CLASS:
                case TokenType.KW_USE:
                case TokenType.KW_FUNCTION:
                    return;
                default:
                    break;
            }

            this.advance();
        }
    }


    // =====================================================================
    //  SECTION 1 — PROGRAM (top-level)
    // =====================================================================

    /**
     * Точка входа в парсер.
     *
     * Program = { UseDeclaration } { FunctionDecl | ClassDecl } MainDecl
     *
     * MainDecl может выглядеть как:
     *   `main() { … }`                  — краткая форма
     *   `void function main() { … }`    — полная void-форма
     *   `int function main() { … }`     — с возвратом int
     */
    parse(): Program {
        const programLoc = this.here();

        // 1. Собираем use-декларации (только в начале файла)
        const imports = this.parseImports();

        // 2. Собираем объявления верхнего уровня (функции, классы)
        const declarations: TopLevelDecl[] = [];
        let main: FunctionDecl | null = null;

        while (!this.isAtEnd()) {
            // Проверяем: это main() в краткой форме?
            if (this.currentType() === TokenType.KW_MAIN && this.peek(1).type === TokenType.LPAREN) {
                if (main !== null) {
                    this.errors.addError(this.file, this.currentLine(),
                        "only one 'main()' function is allowed per program");
                }
                main = this.parseMainShort();
                continue;
            }

            // Проверяем: это объявление функции (returnType function name ...)?
            // или main в полной форме (returnType function main ...)?
            if (this.looksLikeFunctionDecl()) {
                const funcDecl = this.parseFunctionDecl();
                if (funcDecl === null) continue;

                if (funcDecl.name === 'main') {
                    if (main !== null) {
                        this.errors.addError(this.file, funcDecl.loc.line,
                            "only one 'main()' function is allowed per program");
                    }
                    main = funcDecl;
                } else {
                    declarations.push(funcDecl);
                }
                continue;
            }

            // Проверяем: это объявление класса?
            if (this.currentType() === TokenType.KW_CLASS) {
                const classDecl = this.parseClassDecl();
                if (classDecl !== null) {
                    declarations.push(classDecl);
                }
                continue;
            }

            // Ничего не подошло — ошибка.
            this.errors.addError(this.file, this.currentLine(),
                `unexpected ${tokenDisplayValue(this.current())} at top level`);
            this.advance();
        }

        // 3. Проверяем, что main() была найдена.
        if (main === null) {
            this.errors.addError(this.file, this.currentLine(),
                "no 'main()' function found");
            // Создаём пустой main для корректности AST.
            main = {
                kind: 'FunctionDecl',
                loc: programLoc,
                returnType: { kind: 'PrimitiveType', loc: programLoc, name: 'void' },
                name: 'main',
                params: [],
                body: { kind: 'Block', loc: programLoc, statements: [] },
            };
        }

        return {
            kind: 'Program',
            loc: programLoc,
            imports,
            declarations,
            main,
        };
    }

    // =====================================================================
    //  SECTION 2 — IMPORTS
    // =====================================================================

    /**
     * Парсит последовательность `use` деклараций в начале файла.
     *
     * UseDeclaration = "use" IDENTIFIER ";"
     */
    private parseImports(): UseDeclaration[] {
        const imports: UseDeclaration[] = [];

        while (this.currentType() === TokenType.KW_USE) {
            const useLoc = this.here();
            this.advance(); // потребляем 'use'

            const nameTok = this.expect(TokenType.IDENTIFIER, "after 'use'");
            if (nameTok === null) {
                this.synchronize();
                continue;
            }

            this.expect(TokenType.SEMICOLON, "after library name");

            imports.push({
                kind: 'UseDeclaration',
                loc: useLoc,
                libraryName: nameTok.value,
            });
        }

        return imports;
    }

    // =====================================================================
    //  SECTION 3 — LOOKAHEAD HELPERS
    // =====================================================================

    /**
     * Определяет, выглядит ли текущая позиция как начало объявления функции:
     *   returnType "function" name "("
     *
     * Примеры:
     *   `int function foo(…)`
     *   `void function main(…)`
     *   `float function bar(…)`
     *   `dyn_array<int> function baz(…)`
     *
     * НЕ потребляет ни одного токена.
     */
    private looksLikeFunctionDecl(): boolean {
        if (!isTypeStart(this.currentType())) return false;

        // Нужно заглянуть вперёд через тип (который может быть многотокенным:
        // array<int, 5>, dyn_array<string>, time.stamp).
        // Вместо полного разбора типа считаем, сколько токенов он занимает.
        const saved = this.pos;
        const result = this.trySkipType() && this.currentType() === TokenType.KW_FUNCTION;
        this.pos = saved; // откатываем — ничего не потреблено
        return result;
    }

    /**
     * Пытается «пропустить» один тип начиная с текущей позиции.
     * Возвращает true, если пропуск удался; позиция продвинута за последний
     * токен типа.  Используется ТОЛЬКО для lookahead.
     *
     * Поддерживает:
     *   • Примитивы:     int, float, string, char, bool, void
     *   • array<T, N>:   array < Type , INT_LITERAL >
     *   • dyn_array<T>:  dyn_array < Type >
     *   • Qualified:     identifier . identifier
     *   • Class:         identifier
     */
    private trySkipType(): boolean {
        switch (this.currentType()) {
            case TokenType.KW_INT:
            case TokenType.KW_FLOAT:
            case TokenType.KW_STRING:
            case TokenType.KW_CHAR:
            case TokenType.KW_BOOL:
            case TokenType.KW_VOID:
                this.pos++;
                return true;

            case TokenType.KW_ARRAY:
                // array < Type , INT > — нужно найти парную >
                this.pos++; // array
                if (this.currentType() !== TokenType.LT) return false;
                this.pos++; // <
                if (!this.trySkipType()) return false; // element type
                if (this.currentType() !== TokenType.COMMA) return false;
                this.pos++; // ,
                if (this.currentType() !== TokenType.INT_LITERAL) return false;
                this.pos++; // size
                if (this.currentType() !== TokenType.GT) return false;
                this.pos++; // >
                return true;

            case TokenType.KW_DYN_ARRAY:
                this.pos++; // dyn_array
                if (this.currentType() !== TokenType.LT) return false;
                this.pos++; // <
                if (!this.trySkipType()) return false; // element type
                if (this.currentType() !== TokenType.GT) return false;
                this.pos++; // >
                return true;

            case TokenType.IDENTIFIER:
                this.pos++; // identifier
                // Qualified type:  identifier.identifier
                if (this.currentType() === TokenType.DOT &&
                    this.peek(1).type === TokenType.IDENTIFIER) {
                    this.pos += 2; // . identifier
                }
                return true;

            default:
                return false;
        }
    }

    /**
     * Определяет, является ли текущая позиция началом объявления переменной
     * (или множественного объявления) внутри блока:
     *   type identifier ("=" | "," | ";")
     *
     * Нужно для различения:
     *   `int x = 5;`            — объявление переменной
     *   `x = 5;`                — присваивание
     *   `console.write("hi");`  — вызов метода (expression statement)
     */
    private looksLikeVarDecl(): boolean {
        if (!isTypeStart(this.currentType())) return false;

        // Особый случай: если текущий токен — IDENTIFIER, это может быть
        // как тип (Point2D, gui.Window), так и начало выражения (myVar).
        // Разрешаем:
        //   IDENTIFIER IDENTIFIER   → объявление (Point2D p)
        //   IDENTIFIER . IDENTIFIER IDENTIFIER → объявление (gui.Window w)
        //   IDENTIFIER = …          → присваивание (НЕ объявление)
        //   IDENTIFIER . method()   → выражение (НЕ объявление)
        //   IDENTIFIER ( …          → вызов функции (НЕ объявление)

        if (this.currentType() === TokenType.IDENTIFIER) {
            const next = this.peek(1).type;
            // identifier identifier → var decl (ClassType)
            if (next === TokenType.IDENTIFIER) return true;
            // identifier . identifier identifier → var decl (QualifiedType)
            if (next === TokenType.DOT &&
                this.peek(2).type === TokenType.IDENTIFIER &&
                this.peek(3).type === TokenType.IDENTIFIER) return true;
            // Всё остальное — не объявление.
            return false;
        }

        // Для примитивных типов, array, dyn_array — всегда объявление.
        return true;
    }


    // =====================================================================
    //  SECTION 4 — TYPE PARSING
    // =====================================================================

    /**
     * Парсит один тип.
     *
     * Type =
     *   | "int" | "float" | "string" | "char" | "bool" | "void"
     *   | "array" "<" Type "," INT_LITERAL ">"
     *   | "dyn_array" "<" Type ">"
     *   | IDENTIFIER "." IDENTIFIER        // qualified type
     *   | IDENTIFIER                        // class type
     */
    private parseType(): TypeNode | null {
        const typeLoc = this.here();

        // ── Примитивные типы ─────────────────────────────────────────
        switch (this.currentType()) {
            case TokenType.KW_INT:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'int' };
            case TokenType.KW_FLOAT:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'float' };
            case TokenType.KW_STRING:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'string' };
            case TokenType.KW_CHAR:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'char' };
            case TokenType.KW_BOOL:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'bool' };
            case TokenType.KW_VOID:
                this.advance();
                return { kind: 'PrimitiveType', loc: typeLoc, name: 'void' };
        }

        // ── array<T, N> ─────────────────────────────────────────────
        if (this.currentType() === TokenType.KW_ARRAY) {
            return this.parseArrayType();
        }

        // ── dyn_array<T> ────────────────────────────────────────────
        if (this.currentType() === TokenType.KW_DYN_ARRAY) {
            return this.parseDynArrayType();
        }

        // ── IDENTIFIER (ClassType или QualifiedType) ────────────────
        if (this.currentType() === TokenType.IDENTIFIER) {
            const ident = this.advance();

            // QualifiedType: identifier.identifier
            if (this.currentType() === TokenType.DOT &&
                this.peek(1).type === TokenType.IDENTIFIER) {
                this.advance(); // потребляем '.'
                const name = this.advance();
                return {
                    kind: 'QualifiedType',
                    loc: typeLoc,
                    qualifier: ident.value,
                    name: name.value,
                };
            }

            // ClassType: просто identifier
            return {
                kind: 'ClassType',
                loc: typeLoc,
                name: ident.value,
            };
        }

        // ── Ошибка ──────────────────────────────────────────────────
        this.errors.addError(this.file, this.currentLine(),
            `expected type but found ${tokenDisplayValue(this.current())}`);
        return null;
    }

    /**
     * Парсит `array<ElementType, Size>`.
     * Предусловие: текущий токен = KW_ARRAY.
     */
    private parseArrayType(): ArrayType | null {
        const typeLoc = this.here();
        this.advance(); // потребляем 'array'

        if (!this.expect(TokenType.LT, "after 'array'")) return null;

        const elementType = this.parseType();
        if (elementType === null) return null;

        if (!this.expect(TokenType.COMMA, "in array type")) return null;

        const sizeTok = this.expect(TokenType.INT_LITERAL, "for array size");
        if (sizeTok === null) return null;
        const size = parseInt(sizeTok.value, 10);

        if (size <= 0) {
            this.errors.addError(this.file, sizeTok.line,
                `array size must be a positive integer (got ${size})`);
        }

        if (!this.expect(TokenType.GT, "after array size")) return null;

        return {
            kind: 'ArrayType',
            loc: typeLoc,
            elementType,
            size: Math.max(size, 1), // защита от нуля/отрицательных для корректности AST
        };
    }

    /**
     * Парсит `dyn_array<ElementType>`.
     * Предусловие: текущий токен = KW_DYN_ARRAY.
     */
    private parseDynArrayType(): DynArrayType | null {
        const typeLoc = this.here();
        this.advance(); // потребляем 'dyn_array'

        if (!this.expect(TokenType.LT, "after 'dyn_array'")) return null;

        const elementType = this.parseType();
        if (elementType === null) return null;

        if (!this.expect(TokenType.GT, "after element type")) return null;

        return {
            kind: 'DynArrayType',
            loc: typeLoc,
            elementType,
        };
    }


    // =====================================================================
    //  SECTION 5 — FUNCTION DECLARATIONS
    // =====================================================================

    /**
     * Парсит main() в краткой форме.
     *
     * Синтаксис: `main() { body }`
     *
     * Предусловие: current = KW_MAIN, peek(1) = LPAREN.
     */
    private parseMainShort(): FunctionDecl {
        const mainLoc = this.here();
        this.advance(); // потребляем 'main'

        this.expect(TokenType.LPAREN, "after 'main'");
        this.expect(TokenType.RPAREN, "in 'main()'");

        const body = this.parseBlock();

        return {
            kind: 'FunctionDecl',
            loc: mainLoc,
            returnType: { kind: 'PrimitiveType', loc: mainLoc, name: 'void' },
            name: 'main',
            params: [],
            body,
        };
    }

    /**
     * Парсит объявление функции в полной форме.
     *
     * Синтаксис: `returnType "function" name "(" params ")" block`
     *
     * Предусловие: looksLikeFunctionDecl() вернул true.
     */
    private parseFunctionDecl(): FunctionDecl | null {
        const funcLoc = this.here();

        // Парсим тип возврата
        const returnType = this.parseType();
        if (returnType === null) {
            this.synchronize();
            return null;
        }

        // Потребляем 'function'
        this.expect(TokenType.KW_FUNCTION, "in function declaration");

        // Имя функции (IDENTIFIER или KW_MAIN)
        let name: string;
        if (this.currentType() === TokenType.KW_MAIN) {
            name = 'main';
            this.advance();
        } else {
            const nameTok = this.expect(TokenType.IDENTIFIER, "for function name");
            if (nameTok === null) {
                this.synchronize();
                return null;
            }
            name = nameTok.value;
        }

        // Параметры
        if (!this.expect(TokenType.LPAREN, `after function name '${name}'`)) {
            this.synchronize();
            return null;
        }
        const params = this.parseParameterList();
        this.expect(TokenType.RPAREN, "after parameters");

        // Тело
        const body = this.parseBlock();

        return {
            kind: 'FunctionDecl',
            loc: funcLoc,
            returnType,
            name,
            params,
            body,
        };
    }

    /**
     * Парсит список параметров (внутри скобок, без самих скобок).
     *
     * ParameterList = [ Parameter { "," Parameter } ]
     * Parameter = Type IDENTIFIER [ "=" Expression ]
     */
    private parseParameterList(): Parameter[] {
        const params: Parameter[] = [];

        if (this.currentType() === TokenType.RPAREN) {
            return params; // пустой список
        }

        while (true) {
            const param = this.parseOneParameter();
            if (param !== null) {
                params.push(param);
            }

            if (!this.match(TokenType.COMMA)) break;
        }

        return params;
    }

    /** Парсит один параметр: `Type name [ = defaultValue ]`. */
    private parseOneParameter(): Parameter | null {
        const paramLoc = this.here();

        const paramType = this.parseType();
        if (paramType === null) return null;

        const nameTok = this.expect(TokenType.IDENTIFIER, "for parameter name");
        if (nameTok === null) return null;

        let defaultValue: Expression | null = null;
        if (this.match(TokenType.ASSIGN)) {
            defaultValue = this.parseExpression();
        }

        return {
            kind: 'Parameter',
            loc: paramLoc,
            paramType,
            name: nameTok.value,
            defaultValue,
        };
    }


    // =====================================================================
    //  SECTION 6 — CLASS DECLARATIONS
    // =====================================================================

    /**
     * Парсит объявление класса.
     *
     * ClassDecl = "class" IDENTIFIER [ "extends" IDENTIFIER ] "{" ClassBody "}" [";"]
     * ClassBody = { AccessLabel | ClassMember }
     * AccessLabel = ("public" | "private") ":"
     * ClassMember = FieldDecl | MethodDecl | ConstructorDecl | DestructorDecl
     */
    private parseClassDecl(): ClassDecl | null {
        const classLoc = this.here();
        this.advance(); // потребляем 'class'

        const nameTok = this.expect(TokenType.IDENTIFIER, "for class name");
        if (nameTok === null) {
            this.synchronize();
            return null;
        }
        const className = nameTok.value;

        // Наследование (опционально)
        let parentClass: string | null = null;
        if (this.match(TokenType.KW_EXTENDS)) {
            const parentTok = this.expect(TokenType.IDENTIFIER, "after 'extends'");
            if (parentTok !== null) {
                parentClass = parentTok.value;
            }
        }

        if (!this.expect(TokenType.LBRACE, `after class name '${className}'`)) {
            this.synchronize();
            return null;
        }

        // Парсим тело класса
        const members = this.parseClassBody(className);

        this.expect(TokenType.RBRACE, `at end of class '${className}'`);

        // Необязательная ';' после '}'
        this.match(TokenType.SEMICOLON);

        return {
            kind: 'ClassDecl',
            loc: classLoc,
            name: className,
            parentClass,
            members,
        };
    }

    /**
     * Парсит тело класса (всё между { и }).
     *
     * Текущий модификатор доступа по умолчанию — public.
     * Метки `public:` / `private:` переключают модификатор.
     */
    private parseClassBody(className: string): ClassMember[] {
        const members: ClassMember[] = [];
        let currentAccess: AccessModifier = 'public';

        while (!this.isAtEnd() && this.currentType() !== TokenType.RBRACE) {
            // Метка доступа: public: или private:
            if ((this.currentType() === TokenType.KW_PUBLIC ||
                 this.currentType() === TokenType.KW_PRIVATE) &&
                this.peek(1).type === TokenType.COLON) {
                currentAccess = this.currentType() === TokenType.KW_PUBLIC ? 'public' : 'private';
                this.advance(); // потребляем public/private
                this.advance(); // потребляем ':'
                continue;
            }

            // Конструктор: constructor ClassName(…) { … }
            if (this.currentType() === TokenType.KW_CONSTRUCTOR) {
                const ctor = this.parseConstructor(className, currentAccess);
                if (ctor !== null) members.push(ctor);
                continue;
            }

            // Деструктор: destructor ~ClassName() { … }
            if (this.currentType() === TokenType.KW_DESTRUCTOR) {
                const dtor = this.parseDestructor(className, currentAccess);
                if (dtor !== null) members.push(dtor);
                continue;
            }

            // Метод: returnType function name(…) { … }
            if (this.looksLikeFunctionDecl()) {
                const method = this.parseClassMethod(currentAccess);
                if (method !== null) members.push(method);
                continue;
            }

            // Поле: type name [= initializer] [, name2 …] ;
            if (isTypeStart(this.currentType())) {
                const fields = this.parseClassFields(currentAccess);
                members.push(...fields);
                continue;
            }

            // Ошибка
            this.errors.addError(this.file, this.currentLine(),
                `unexpected ${tokenDisplayValue(this.current())} in class body`);
            this.advance();
        }

        return members;
    }

    /**
     * Парсит одно или несколько полей класса.
     *
     * Синтаксис: `type name1 [= init1], name2 [= init2], … ;`
     *
     * Пример: `int xPos, yPos;`
     *
     * Каждое имя порождает отдельный ClassField.
     */
    private parseClassFields(access: AccessModifier): ClassField[] {
        const fieldLoc = this.here();
        const fieldType = this.parseType();
        if (fieldType === null) {
            this.synchronize();
            return [];
        }

        const fields: ClassField[] = [];

        while (true) {
            const nameTok = this.expect(TokenType.IDENTIFIER, "for field name");
            if (nameTok === null) {
                this.synchronize();
                return fields;
            }

            let initializer: Expression | null = null;
            if (this.match(TokenType.ASSIGN)) {
                initializer = this.parseExpression();
            }

            fields.push({
                kind: 'ClassField',
                loc: this.locOf(nameTok),
                access,
                fieldType,
                name: nameTok.value,
                initializer,
            });

            if (!this.match(TokenType.COMMA)) break;
        }

        this.expect(TokenType.SEMICOLON, "after field declaration");
        return fields;
    }

    /**
     * Парсит метод класса.
     *
     * Синтаксис: `returnType function name(params) { body }`
     */
    private parseClassMethod(access: AccessModifier): ClassMethod | null {
        const methodLoc = this.here();

        const returnType = this.parseType();
        if (returnType === null) {
            this.synchronize();
            return null;
        }

        this.expect(TokenType.KW_FUNCTION, "in method declaration");

        const nameTok = this.expect(TokenType.IDENTIFIER, "for method name");
        if (nameTok === null) {
            this.synchronize();
            return null;
        }

        this.expect(TokenType.LPAREN, `after method name '${nameTok.value}'`);
        const params = this.parseParameterList();
        this.expect(TokenType.RPAREN, "after method parameters");

        const body = this.parseBlock();

        return {
            kind: 'ClassMethod',
            loc: methodLoc,
            access,
            returnType,
            name: nameTok.value,
            params,
            body,
        };
    }

    /**
     * Парсит конструктор.
     *
     * Синтаксис: `constructor ClassName(params) { body }`
     */
    private parseConstructor(className: string, access: AccessModifier): ClassConstructor | null {
        const ctorLoc = this.here();
        this.advance(); // потребляем 'constructor'

        // Имя должно совпадать с именем класса
        const nameTok = this.expect(TokenType.IDENTIFIER, "after 'constructor'");
        if (nameTok === null) {
            this.synchronize();
            return null;
        }
        if (nameTok.value !== className) {
            this.errors.addError(this.file, nameTok.line,
                `constructor name '${nameTok.value}' does not match class name '${className}'`);
        }

        this.expect(TokenType.LPAREN, "after constructor name");
        const params = this.parseParameterList();
        this.expect(TokenType.RPAREN, "after constructor parameters");

        const body = this.parseBlock();

        return {
            kind: 'ClassConstructor',
            loc: ctorLoc,
            access,
            className,
            params,
            body,
        };
    }

    /**
     * Парсит деструктор.
     *
     * Синтаксис: `destructor ~ClassName() { body }`
     */
    private parseDestructor(className: string, access: AccessModifier): ClassDestructor | null {
        const dtorLoc = this.here();
        this.advance(); // потребляем 'destructor'

        // Ожидаем '~'
        if (!this.expect(TokenType.TILDE, "before destructor name")) {
            this.synchronize();
            return null;
        }

        // Имя должно совпадать с именем класса
        const nameTok = this.expect(TokenType.IDENTIFIER, "after '~'");
        if (nameTok === null) {
            this.synchronize();
            return null;
        }
        if (nameTok.value !== className) {
            this.errors.addError(this.file, nameTok.line,
                `destructor name '${nameTok.value}' does not match class name '${className}'`);
        }

        this.expect(TokenType.LPAREN, "after destructor name");
        this.expect(TokenType.RPAREN, "destructor cannot have parameters");

        const body = this.parseBlock();

        return {
            kind: 'ClassDestructor',
            loc: dtorLoc,
            access,
            className,
            body,
        };
    }


    // =====================================================================
    //  SECTION 7 — BLOCKS & STATEMENTS
    // =====================================================================

    /**
     * Парсит блок: `{ statement* }`.
     *
     * Если открывающая `{` отсутствует, регистрируется ошибка и
     * возвращается пустой блок.
     */
    private parseBlock(): Block {
        const blockLoc = this.here();

        if (!this.expect(TokenType.LBRACE, "to open block")) {
            return { kind: 'Block', loc: blockLoc, statements: [] };
        }

        const statements: Statement[] = [];

        while (!this.isAtEnd() && this.currentType() !== TokenType.RBRACE) {
            const stmt = this.parseStatement();
            if (stmt !== null) {
                statements.push(stmt);
            }
        }

        this.expect(TokenType.RBRACE, "to close block");

        return {
            kind: 'Block',
            loc: blockLoc,
            statements,
        };
    }

    /**
     * Парсит одну инструкцию.
     *
     * Statement =
     *   | VariableDecl ";"
     *   | IfStmt
     *   | WhileStmt
     *   | DoWhileStmt
     *   | ForStmt
     *   | ReturnStmt ";"
     *   | BreakStmt ";"
     *   | ContinueStmt ";"
     *   | Assignment ";"
     *   | ExpressionStmt ";"
     */
    private parseStatement(): Statement | null {
        switch (this.currentType()) {
            case TokenType.KW_IF:
                return this.parseIfStmt();

            case TokenType.KW_WHILE:
                return this.parseWhileStmt();

            case TokenType.KW_DO:
                return this.parseDoWhileStmt();

            case TokenType.KW_FOR:
                return this.parseForStmt();

            case TokenType.KW_RETURN:
                return this.parseReturnStmt();

            case TokenType.KW_BREAK: {
                const breakLoc = this.here();
                this.advance();
                this.expect(TokenType.SEMICOLON, "after 'break'");
                return { kind: 'BreakStmt', loc: breakLoc };
            }

            case TokenType.KW_CONTINUE: {
                const contLoc = this.here();
                this.advance();
                this.expect(TokenType.SEMICOLON, "after 'continue'");
                return { kind: 'ContinueStmt', loc: contLoc };
            }

            default:
                break;
        }

        // Объявление переменной: type name [= expr] ;
        if (this.looksLikeVarDecl()) {
            return this.parseVarDeclStatement();
        }

        // Присваивание или выражение-инструкция
        return this.parseAssignmentOrExprStmt();
    }

    // ── Variable declaration statement ──────────────────────────────────

    /**
     * Парсит объявление переменной (или нескольких через запятую).
     *
     * Синтаксис:
     *   `type name [ = expr ] ;`
     *   `type name1, name2, name3 ;`
     *   `Point2D p(30, 40) ;`     — конструктор с аргументами
     *
     * Множественные объявления `int a, b, c;` порождают ПЕРВЫЙ VariableDecl
     * и возвращают его; остальные добавляются как последовательные
     * инструкции — для этого используем обёртку, которая порождает
     * несколько VariableDecl подряд.
     *
     * Но поскольку parseStatement() возвращает одну инструкцию,
     * а множественные объявления — это несколько, нам нужна стратегия.
     * Решение: первый VariableDecl возвращается из parseStatement(),
     * а остальные «вставляются» в statements-массив через parseBlock.
     *
     * Проще: парсим ВСЕ имена, но каждое — отдельный VariableDecl.
     * Возвращаем первый, а остальные добавляем… нет, это усложняет API.
     *
     * Окончательное решение: возвращаем первый, а для множественных
     * объявлений парсер обрабатывает их в parseBlock() через цикл.
     *
     * UPD: Простейшее решение — parseVarDeclStatement возвращает
     * первый VariableDecl, но НЕ ПОТРЕБЛЯЕТ ';' для остальных
     * имён — парсим их все как отдельные Statement здесь.
     */
    private parseVarDeclStatement(): VariableDecl | null {
        const declLoc = this.here();

        const varType = this.parseType();
        if (varType === null) {
            this.synchronize();
            return null;
        }

        const result = this.parseOneVarDecl(varType, declLoc);

        // Для множественных объявлений: `int a, b, c;`
        // НЕ поддерживаем в этой версии для простоты.
        // Множественные объявления разрешены только в ClassField.
        // В теле функции пишем: `int a; int b; int c;`

        this.expect(TokenType.SEMICOLON, "after variable declaration");
        return result;
    }

    /**
     * Парсит одну переменную (после того как тип уже распознан).
     *
     *   name [ = expr ]
     *   name ( args )         — для вызова конструктора
     */
    private parseOneVarDecl(varType: TypeNode, declLoc: SourceLocation): VariableDecl | null {
        const nameTok = this.expect(TokenType.IDENTIFIER, "for variable name");
        if (nameTok === null) {
            return null;
        }

        let initializer: Expression | null = null;
        let constructorArgs: Argument[] | null = null;

        if (this.match(TokenType.ASSIGN)) {
            // `type name = expression`
            initializer = this.parseExpression();
        } else if (this.currentType() === TokenType.LPAREN) {
            // `ClassName name(args)` — конструктор с аргументами
            this.advance(); // потребляем '('
            constructorArgs = this.parseArgumentList();
            this.expect(TokenType.RPAREN, "after constructor arguments");
        }

        return {
            kind: 'VariableDecl',
            loc: this.locOf(nameTok),
            varType,
            name: nameTok.value,
            initializer,
            constructorArgs,
        };
    }

    // ── Assignment or expression statement ──────────────────────────────

    /**
     * Парсит присваивание или выражение-инструкцию.
     *
     * Стратегия: парсим выражение, затем смотрим, следует ли оператор
     * присваивания.  Если да — это AssignmentStmt.  Если нет — это
     * ExpressionStmt.
     *
     * Примеры:
     *   `money = 25000;`       → AssignmentStmt
     *   `P[0] = 72;`           → AssignmentStmt
     *   `label.text = "hi";`   → AssignmentStmt
     *   `x += 1;`              → AssignmentStmt
     *   `console.write("hi");` → ExpressionStmt
     *   `draw_line(10);`       → ExpressionStmt
     */
    private parseAssignmentOrExprStmt(): Statement | null {
        const stmtLoc = this.here();

        const expr = this.parseExpression();
        if (expr === null) {
            this.synchronize();
            return null;
        }

        // Проверяем: за выражением следует оператор присваивания?
        const assignOp = isAssignmentOp(this.currentType());

        if (assignOp !== null) {
            // Проверяем, является ли выражение допустимой целью.
            if (!isAssignmentTarget(expr)) {
                this.errors.addError(this.file, stmtLoc.line,
                    'invalid assignment target');
                this.advance(); // потребляем оператор
                this.parseExpression(); // потребляем правую часть
                this.expect(TokenType.SEMICOLON, "after assignment");
                return null;
            }

            // Проверка на `=` в условии: здесь не нужна, т.к. это
            // parseStatement, а не условие.  Но проверим на `if (x = 5)`
            // в parseIfStmt и других местах.

            this.advance(); // потребляем оператор присваивания

            const value = this.parseExpression();
            if (value === null) {
                this.synchronize();
                return null;
            }

            this.expect(TokenType.SEMICOLON, "after assignment");

            return {
                kind: 'AssignmentStmt',
                loc: stmtLoc,
                target: expr as AssignmentTarget,
                operator: assignOp,
                value,
            };
        }

        // Это выражение-инструкция.
        this.expect(TokenType.SEMICOLON, "after expression");

        return {
            kind: 'ExpressionStmt',
            loc: stmtLoc,
            expression: expr,
        };
    }


    // ── if ──────────────────────────────────────────────────────────────

    /**
     * Парсит условный оператор.
     *
     * IfStmt = "if" "(" Expression ")" Block
     *          { "else" "if" "(" Expression ")" Block }
     *          [ "else" Block ]
     */
    private parseIfStmt(): IfStmt {
        const ifLoc = this.here();
        this.advance(); // потребляем 'if'

        // Проверка: if без скобок
        if (this.currentType() !== TokenType.LPAREN) {
            this.errors.addError(this.file, this.currentLine(),
                "missing '(' after 'if'");
        }

        const condition = this.parseParenthesizedCondition();
        const thenBlock = this.parseBlock();

        const elseIfClauses: ElseIfClause[] = [];
        let elseBlock: Block | null = null;

        while (this.currentType() === TokenType.KW_ELSE) {
            const elseLoc = this.here();
            this.advance(); // потребляем 'else'

            if (this.currentType() === TokenType.KW_IF) {
                // else if
                this.advance(); // потребляем 'if'

                const elseIfCondition = this.parseParenthesizedCondition();
                const elseIfBlock = this.parseBlock();

                elseIfClauses.push({
                    loc: elseLoc,
                    condition: elseIfCondition,
                    block: elseIfBlock,
                });
            } else if (this.currentType() === TokenType.LPAREN) {
                // else (condition) — ошибка!
                this.errors.addError(this.file, this.currentLine(),
                    "'else' cannot have a condition, use 'else if' instead");
                this.parseParenthesizedCondition(); // потребляем для recovery
                elseBlock = this.parseBlock();
                break;
            } else {
                // else { … }
                elseBlock = this.parseBlock();
                break;
            }
        }

        return {
            kind: 'IfStmt',
            loc: ifLoc,
            condition,
            thenBlock,
            elseIfClauses,
            elseBlock,
        };
    }

    /**
     * Парсит условие в скобках: `( expression )`.
     *
     * Дополнительная проверка: предупреждение при `=` вместо `==`.
     */
    private parseParenthesizedCondition(): Expression {
        this.expect(TokenType.LPAREN, "before condition");

        if (this.currentType() === TokenType.RPAREN) {
            this.errors.addError(this.file, this.currentLine(),
                'condition cannot be empty');
            this.advance(); // потребляем ')'
            // Возвращаем false как заглушку
            return { kind: 'BoolLiteral', loc: this.here(), value: false };
        }

        const expr = this.parseExpression();

        // Проверка: присваивание в условии
        if (expr !== null && expr.kind === 'Identifier' &&
            this.currentType() === TokenType.ASSIGN) {
            // Пользователь написал if (x = 5)
            // К сожалению, на этом этапе '=' уже не был потреблён
            // (parseExpression не разбирает '=').
            // Однако проверку `=` в условии корректнее делать
            // в семантическом анализаторе, где доступен полный контекст.
        }

        this.expect(TokenType.RPAREN, "after condition");

        return expr ?? { kind: 'BoolLiteral', loc: this.here(), value: false };
    }

    // ── while ──────────────────────────────────────────────────────────

    /**
     * WhileStmt = "while" "(" Expression ")" Block
     */
    private parseWhileStmt(): WhileStmt {
        const whileLoc = this.here();
        this.advance(); // потребляем 'while'

        const condition = this.parseParenthesizedCondition();
        const body = this.parseBlock();

        return {
            kind: 'WhileStmt',
            loc: whileLoc,
            condition,
            body,
        };
    }

    // ── do-while ────────────────────────────────────────────────────────

    /**
     * DoWhileStmt = "do" Block "while" "(" Expression ")" ";"
     */
    private parseDoWhileStmt(): DoWhileStmt {
        const doLoc = this.here();
        this.advance(); // потребляем 'do'

        const body = this.parseBlock();

        this.expect(TokenType.KW_WHILE, "after 'do' block");
        const condition = this.parseParenthesizedCondition();
        this.expect(TokenType.SEMICOLON, "after 'do-while' condition");

        return {
            kind: 'DoWhileStmt',
            loc: doLoc,
            body,
            condition,
        };
    }

    // ── for ─────────────────────────────────────────────────────────────

    /**
     * ForStmt = "for" "(" VarDecl ";" Expression ";" Assignment ")" Block
     *
     * Пример: `for (int i = 0; i < 10; i += 1) { … }`
     *
     * init — обязательно объявление переменной.
     * update — обязательно присваивание (не произвольное выражение).
     */
    private parseForStmt(): ForStmt {
        const forLoc = this.here();
        this.advance(); // потребляем 'for'

        this.expect(TokenType.LPAREN, "after 'for'");

        // ── Инициализация: type name = expr ─────────────────────────
        const initLoc = this.here();
        const initType = this.parseType();
        if (initType === null) {
            this.synchronize();
            return this.dummyFor(forLoc);
        }
        const initDecl = this.parseOneVarDecl(initType, initLoc);
        if (initDecl === null) {
            this.synchronize();
            return this.dummyFor(forLoc);
        }

        this.expect(TokenType.SEMICOLON, "after 'for' initialization");

        // ── Условие ─────────────────────────────────────────────────
        const condition = this.parseExpression();
        if (condition === null) {
            this.synchronize();
            return this.dummyFor(forLoc);
        }

        this.expect(TokenType.SEMICOLON, "after 'for' condition");

        // ── Обновление: target op= expr ─────────────────────────────
        const updateLoc = this.here();
        const updateExpr = this.parseExpression();
        if (updateExpr === null) {
            this.synchronize();
            return this.dummyFor(forLoc);
        }

        const updateOp = isAssignmentOp(this.currentType());
        if (updateOp === null) {
            this.errors.addError(this.file, this.currentLine(),
                "expected assignment operator in 'for' update");
            this.synchronize();
            return this.dummyFor(forLoc);
        }

        if (!isAssignmentTarget(updateExpr)) {
            this.errors.addError(this.file, updateLoc.line,
                "invalid assignment target in 'for' update");
        }

        this.advance(); // потребляем оператор присваивания

        const updateValue = this.parseExpression();
        if (updateValue === null) {
            this.synchronize();
            return this.dummyFor(forLoc);
        }

        const update: AssignmentStmt = {
            kind: 'AssignmentStmt',
            loc: updateLoc,
            target: updateExpr as AssignmentTarget,
            operator: updateOp,
            value: updateValue,
        };

        this.expect(TokenType.RPAREN, "after 'for' clauses");

        const body = this.parseBlock();

        return {
            kind: 'ForStmt',
            loc: forLoc,
            init: initDecl,
            condition,
            update,
            body,
        };
    }

    /** Создаёт пустой ForStmt для error recovery. */
    private dummyFor(forLoc: SourceLocation): ForStmt {
        return {
            kind: 'ForStmt',
            loc: forLoc,
            init: {
                kind: 'VariableDecl', loc: forLoc,
                varType: { kind: 'PrimitiveType', loc: forLoc, name: 'int' },
                name: '_dummy', initializer: null, constructorArgs: null,
            },
            condition: { kind: 'BoolLiteral', loc: forLoc, value: false },
            update: {
                kind: 'AssignmentStmt', loc: forLoc,
                target: { kind: 'Identifier', loc: forLoc, name: '_dummy' },
                operator: '=',
                value: { kind: 'IntLiteral', loc: forLoc, value: 0 },
            },
            body: { kind: 'Block', loc: forLoc, statements: [] },
        };
    }

    // ── return ──────────────────────────────────────────────────────────

    /**
     * ReturnStmt = "return" [ Expression ] ";"
     */
    private parseReturnStmt(): ReturnStmt {
        const retLoc = this.here();
        this.advance(); // потребляем 'return'

        let value: Expression | null = null;

        // Если за return сразу стоит ';' — пустой возврат (void).
        if (this.currentType() !== TokenType.SEMICOLON) {
            value = this.parseExpression();
        }

        this.expect(TokenType.SEMICOLON, "after 'return'");

        return {
            kind: 'ReturnStmt',
            loc: retLoc,
            value,
        };
    }


    // =====================================================================
    //  SECTION 8 — EXPRESSIONS (Pratt parsing)
    // =====================================================================

    /**
     * Точка входа в парсинг выражений.
     *
     * Выражения парсятся методом приоритетного восхождения (Pratt parser):
     *   parseExpression()        → вызывает parseBinaryExpr(0)
     *   parseBinaryExpr(minPrec) → парсит левый операнд через parseUnary(),
     *                               затем в цикле «подбирает» бинарные
     *                               операторы с приоритетом ≥ minPrec.
     *   parseUnary()             → обрабатывает '-' и 'not()', затем
     *                               вызывает parsePostfix().
     *   parsePostfix()           → обрабатывает '.', '[', '(' после
     *                               атома; цепочки вроде obj.method(x)[0].
     *   parsePrimary()           → литералы, идентификаторы, '(' expr ')',
     *                               array literal, this, lambda.
     */
    private parseExpression(): Expression | null {
        return this.parseBinaryExpr(0);
    }

    /**
     * Парсит бинарное выражение с приоритетным восхождением.
     *
     * @param minPrec  Минимальный приоритет оператора, который мы готовы
     *                 «подобрать» на данном уровне рекурсии.
     */
    private parseBinaryExpr(minPrec: number): Expression | null {
        let left = this.parseUnary();
        if (left === null) return null;

        while (true) {
            const prec = getBinaryPrecedence(this.currentType());
            if (prec < minPrec) break;

            const opToken = this.advance();
            const op = tokenToBinaryOp(opToken.type);

            // Правая сторона парсится с приоритетом prec + 1,
            // что даёт левую ассоциативность: `a + b + c` → `(a + b) + c`.
            const right = this.parseBinaryExpr(prec + 1);
            if (right === null) return left; // error recovery: сохраняем левую часть

            left = {
                kind: 'BinaryExpr',
                loc: this.locOf(opToken),
                operator: op,
                left,
                right,
            };
        }

        return left;
    }

    /**
     * Парсит унарные операторы.
     *
     * UnaryExpr =
     *   | "-" UnaryExpr              → UnaryMinus
     *   | "not" "(" Expression ")"   → NotExpr
     *   | PostfixExpr
     */
    private parseUnary(): Expression | null {
        // ── Унарный минус ────────────────────────────────────────────
        if (this.currentType() === TokenType.MINUS) {
            const minusLoc = this.here();
            this.advance(); // потребляем '-'

            const operand = this.parseUnary(); // рекурсия для --x, -(-(x))
            if (operand === null) return null;

            return {
                kind: 'UnaryMinus',
                loc: minusLoc,
                operand,
            };
        }

        // ── not(expr) ───────────────────────────────────────────────
        if (this.currentType() === TokenType.KW_NOT) {
            const notLoc = this.here();
            this.advance(); // потребляем 'not'

            if (!this.expect(TokenType.LPAREN, "after 'not'")) {
                return null;
            }

            const argument = this.parseExpression();
            if (argument === null) return null;

            this.expect(TokenType.RPAREN, "after 'not' argument");

            return {
                kind: 'NotExpr',
                loc: notLoc,
                argument,
            };
        }

        // ── Постфиксные выражения ───────────────────────────────────
        return this.parsePostfix();
    }

    /**
     * Парсит постфиксные операции: вызов метода, доступ к свойству,
     * индексный доступ.
     *
     * PostfixExpr = Primary { PostfixOp }
     * PostfixOp =
     *   | "." IDENTIFIER "(" args ")"    → MethodCall
     *   | "." IDENTIFIER                  → PropertyAccess
     *   | "[" Expression "]"              → IndexAccess
     *   | "(" args ")"                    → FunctionCall (только для Identifier)
     */
    private parsePostfix(): Expression | null {
        let expr = this.parsePrimary();
        if (expr === null) return null;

        while (true) {
            // ── Вызов функции: identifier( args ) ────────────────────
            // Вызов функции разрешён только сразу после parsePrimary,
            // если результат — Identifier.  Но для единообразия обрабатываем
            // здесь в цикле.
            if (this.currentType() === TokenType.LPAREN && expr.kind === 'Identifier') {
                expr = this.finishFunctionCall(expr as IdentifierExpr);
                continue;
            }

            // ── Доступ к свойству или вызов метода: expr.name[(...)] ─
            if (this.currentType() === TokenType.DOT) {
                this.advance(); // потребляем '.'

                const nameTok = this.expect(TokenType.IDENTIFIER, "after '.'");
                if (nameTok === null) return expr; // recovery

                // Это вызов метода?
                if (this.currentType() === TokenType.LPAREN) {
                    this.advance(); // потребляем '('
                    const args = this.parseArgumentList();
                    this.expect(TokenType.RPAREN, "after method arguments");

                    expr = {
                        kind: 'MethodCall',
                        loc: this.locOf(nameTok),
                        object: expr,
                        method: nameTok.value,
                        args,
                    };
                } else {
                    // Доступ к свойству
                    expr = {
                        kind: 'PropertyAccess',
                        loc: this.locOf(nameTok),
                        object: expr,
                        property: nameTok.value,
                    };
                }
                continue;
            }

            // ── Индексный доступ: expr[index] ────────────────────────
            if (this.currentType() === TokenType.LBRACKET) {
                const bracketLoc = this.here();
                this.advance(); // потребляем '['

                const index = this.parseExpression();
                if (index === null) {
                    this.synchronize();
                    return expr;
                }

                this.expect(TokenType.RBRACKET, "after index");

                expr = {
                    kind: 'IndexAccess',
                    loc: bracketLoc,
                    object: expr,
                    index,
                };
                continue;
            }

            // Никаких постфиксных операций — выходим.
            break;
        }

        return expr;
    }

    /**
     * Завершает разбор вызова функции.
     *
     * На входе: identifier уже разобран, текущий токен — '('.
     */
    private finishFunctionCall(callee: IdentifierExpr): FunctionCallExpr {
        this.advance(); // потребляем '('
        const args = this.parseArgumentList();
        this.expect(TokenType.RPAREN, "after function arguments");

        return {
            kind: 'FunctionCall',
            loc: callee.loc,
            callee: callee.name,
            args,
        };
    }

    /**
     * Парсит первичное выражение (атом).
     *
     * Primary =
     *   | INT_LITERAL
     *   | FLOAT_LITERAL
     *   | STRING_LITERAL
     *   | CHAR_LITERAL
     *   | "true" | "false"
     *   | "[" ExprList "]"            → ArrayLiteral
     *   | "this"
     *   | IDENTIFIER
     *   | "div" "(" args ")"          → FunctionCall("div")
     *   | "mod" "(" args ")"          → FunctionCall("mod")
     *   | returnType "function" "(" params ")" block   → Lambda
     *   | "(" Expression ")"          → группировка
     */
    private parsePrimary(): Expression | null {
        const tok = this.current();

        switch (tok.type) {
            // ── Целочисленный литерал ────────────────────────────────
            case TokenType.INT_LITERAL:
                this.advance();
                return {
                    kind: 'IntLiteral',
                    loc: this.locOf(tok),
                    value: parseInt(tok.value, 10),
                };

            // ── Дробный литерал ──────────────────────────────────────
            case TokenType.FLOAT_LITERAL:
                this.advance();
                return {
                    kind: 'FloatLiteral',
                    loc: this.locOf(tok),
                    value: parseFloat(tok.value),
                };

            // ── Строковый литерал ────────────────────────────────────
            case TokenType.STRING_LITERAL:
                this.advance();
                return {
                    kind: 'StringLiteral',
                    loc: this.locOf(tok),
                    value: tok.value,
                };

            // ── Символьный литерал ───────────────────────────────────
            case TokenType.CHAR_LITERAL:
                this.advance();
                return {
                    kind: 'CharLiteral',
                    loc: this.locOf(tok),
                    value: tok.value,
                };

            // ── true / false ────────────────────────────────────────
            case TokenType.KW_TRUE:
                this.advance();
                return { kind: 'BoolLiteral', loc: this.locOf(tok), value: true };

            case TokenType.KW_FALSE:
                this.advance();
                return { kind: 'BoolLiteral', loc: this.locOf(tok), value: false };

            // ── this ────────────────────────────────────────────────
            case TokenType.KW_THIS:
                this.advance();
                return { kind: 'ThisExpr', loc: this.locOf(tok) };

            // ── div(…) и mod(…) ─────────────────────────────────────
            case TokenType.KW_DIV:
            case TokenType.KW_MOD: {
                const funcName = tok.value; // "div" или "mod"
                this.advance();
                if (!this.expect(TokenType.LPAREN, `after '${funcName}'`)) return null;
                const args = this.parseArgumentList();
                this.expect(TokenType.RPAREN, `after '${funcName}' arguments`);
                return {
                    kind: 'FunctionCall',
                    loc: this.locOf(tok),
                    callee: funcName,
                    args,
                };
            }

            // ── Литерал массива: [ expr, expr, … ] ──────────────────
            case TokenType.LBRACKET:
                return this.parseArrayLiteral();

            // ── Группировка / скобки: ( expression ) ────────────────
            case TokenType.LPAREN: {
                this.advance(); // потребляем '('
                const inner = this.parseExpression();
                this.expect(TokenType.RPAREN, "after expression");
                return inner;
            }

            // ── Идентификатор ───────────────────────────────────────
            case TokenType.IDENTIFIER:
                this.advance();
                return {
                    kind: 'Identifier',
                    loc: this.locOf(tok),
                    name: tok.value,
                };

            // ── Лямбда: returnType function(params) { body } ────────
            // Лямбды начинаются с типа, за которым идёт 'function'.
            // Примитивный тип + function — парсим как лямбду.
            case TokenType.KW_VOID:
            case TokenType.KW_INT:
            case TokenType.KW_FLOAT:
            case TokenType.KW_STRING:
            case TokenType.KW_CHAR:
            case TokenType.KW_BOOL:
                // Проверяем: это лямбда или нет?
                // Лямбда: type function ( …
                if (this.peek(1).type === TokenType.KW_FUNCTION) {
                    return this.parseLambda();
                }
                // Иначе — это не выражение, а что-то другое.
                break;

            default:
                break;
        }

        // Ничего не подошло — ошибка.
        this.errors.addError(this.file, this.currentLine(),
            `expected expression but found ${tokenDisplayValue(this.current())}`);
        this.advance(); // пропускаем для recovery
        return null;
    }

    /**
     * Парсит литерал массива: `[ expr, expr, … ]`.
     *
     * Предусловие: текущий токен = LBRACKET.
     */
    private parseArrayLiteral(): ArrayLiteralExpr {
        const arrLoc = this.here();
        this.advance(); // потребляем '['

        const elements: Expression[] = [];

        if (this.currentType() !== TokenType.RBRACKET) {
            while (true) {
                const elem = this.parseExpression();
                if (elem !== null) {
                    elements.push(elem);
                }
                if (!this.match(TokenType.COMMA)) break;
            }
        }

        this.expect(TokenType.RBRACKET, "after array elements");

        return {
            kind: 'ArrayLiteral',
            loc: arrLoc,
            elements,
        };
    }

    /**
     * Парсит лямбда-выражение.
     *
     * Синтаксис: `returnType function ( params ) { body }`
     *
     * Пример: `void function() { label.text = "Clicked!"; }`
     *
     * Предусловие: текущий токен — тип возврата, peek(1) = 'function'.
     */
    private parseLambda(): LambdaExpr | null {
        const lambdaLoc = this.here();

        const returnType = this.parseType();
        if (returnType === null) return null;

        this.expect(TokenType.KW_FUNCTION, "in lambda expression");
        this.expect(TokenType.LPAREN, "after 'function' in lambda");
        const params = this.parseParameterList();
        this.expect(TokenType.RPAREN, "after lambda parameters");

        const body = this.parseBlock();

        return {
            kind: 'Lambda',
            loc: lambdaLoc,
            returnType,
            params,
            body,
        };
    }


    // =====================================================================
    //  SECTION 9 — ARGUMENT LISTS
    // =====================================================================

    /**
     * Парсит список аргументов (внутри скобок, БЕЗ самих скобок).
     *
     * ArgumentList = [ Argument { "," Argument } ]
     * Argument = [ IDENTIFIER "=" ] Expression
     *
     * Именованные аргументы: `sub(arg2=50, arg1=30)`.
     */
    private parseArgumentList(): Argument[] {
        const args: Argument[] = [];

        if (this.currentType() === TokenType.RPAREN) {
            return args; // пустой список
        }

        while (true) {
            const argLoc = this.here();
            let name: string | null = null;

            // Проверяем: это именованный аргумент?
            // identifier = expression (но НЕ identifier == expression)
            if (this.currentType() === TokenType.IDENTIFIER &&
                this.peek(1).type === TokenType.ASSIGN) {
                // Дополнительная проверка: убедимся, что за '=' не идёт '='
                // (т.е. это не '==')
                name = this.current().value;
                this.advance(); // потребляем identifier
                this.advance(); // потребляем '='
            }

            const value = this.parseExpression();
            if (value === null) break;

            args.push({
                loc: argLoc,
                name,
                value,
            });

            if (!this.match(TokenType.COMMA)) break;
        }

        return args;
    }
}
