// =============================================================================
// ide.ts — точка входа для веб-IDE Idyllium
// =============================================================================

import { compileIdyllium, runIdyllium, RunResult } from '../index';
import { Editor } from './editor';
import { Terminal } from './terminal';

const STARTER_CODE = `use console;
use math;
use random;

main() {
    console.write("Добро пожаловать в Idyllium!\\n\\n");

    // Арифметика: деление всегда возвращает float
    int a = 7;
    int b = 4;
    console.write(a, " / ", b, " = ", a / b, "\\n");
    console.write(a, " div ", b, " = ", div(a, b), "\\n");
    console.write(a, " mod ", b, " = ", mod(a, b), "\\n\\n");

    // Массивы
    dyn_array<int> nums = [29, 84, 16, 35, 43];
    nums.add(99);
    console.write("Массив: ", nums, "\\n");
    console.write("Максимум: ", max(nums), "\\n");
    console.write("Сумма: ", sum(nums), "\\n\\n");

    // Цикл и условие
    for (int i = 1; i <= 5; i += 1) {
        if (mod(i, 2) == 0) {
            console.write(i, " — чётное\\n");
        } else {
            console.write(i, " — нечётное\\n");
        }
    }

    // ANSI-цвета
    console.write("\\n");
    console.write("\\e[31m", "Красный ", "\\e[32m", "Зелёный ", "\\e[34m", "Синий", "\\e[0m", "\\n");

    console.write("\\nГотово!\\n");
}
`;

// ── Состояние ───────────────────────────────────────────────────────────────

let editor: Editor | null = null;
let terminal: Terminal | null = null;
let isRunning = false;
let abortController: AbortController | null = null;

// ── Инициализация ───────────────────────────────────────────────────────────

export function init(): void {
    const editorContainer = document.getElementById('editor-container');
    const terminalContainer = document.getElementById('terminal-body');

    if (!editorContainer || !terminalContainer) {
        console.error('Editor or terminal container not found');
        return;
    }

    editor = new Editor(editorContainer, {
        initialValue: STARTER_CODE,
        tabSize: 4,
        fontSize: 15,
    });

    terminal = new Terminal(terminalContainer);
    terminal.printSystem('Idyllium IDE готова к работе.\n', 'info');
    terminal.printSystem('Нажмите "▶ Запустить" или Ctrl+Enter.\n\n', 'info');

    // ── Кнопки ───────────────────────────────────────────────────────
    document.getElementById('btn-run')?.addEventListener('click', handleRun);
    document.getElementById('btn-stop')?.addEventListener('click', handleStop);
    document.getElementById('btn-save')?.addEventListener('click', handleSave);
    document.getElementById('btn-load')?.addEventListener('click', handleLoad);

    // ── Горячие клавиши ──────────────────────────────────────────────
    document.addEventListener('keydown', (e) => {
        if ((e.ctrlKey || e.metaKey) && e.key === 'Enter') {
            e.preventDefault();
            handleRun();
        }
        if ((e.ctrlKey || e.metaKey) && e.key === 's') {
            e.preventDefault();
            handleSave();
        }
        if ((e.ctrlKey || e.metaKey) && e.key === 'o') {
            e.preventDefault();
            handleLoad();
        }
    });

    // ── Resizer ──────────────────────────────────────────────────────
    initResizer();
}

// ── Запуск ──────────────────────────────────────────────────────────────────

async function handleRun(): Promise<void> {
    if (!editor || !terminal || isRunning) return;

    isRunning = true;
    abortController = new AbortController();
    updateButtons();

    terminal.clear();
    editor.clearErrors();
    terminal.printSystem('⏳ Компиляция...\n', 'info');

    const source = editor.getValue();

    try {
        const result = await runIdyllium(source, { console: terminal }, 'main.idyl');

        if (abortController?.signal.aborted) {
            terminal.printSystem('\n⛔ Выполнение прервано.\n', 'info');
        } else if (!result.compilation.success) {
            terminal.printSystem('\n❌ Ошибки компиляции:\n\n', 'error');
            const errorLines: number[] = [];
            for (const err of result.compilation.errors) {
                terminal.printSystem(`  ${err.file}:${err.line}: ${err.message}\n`, 'error');
                errorLines.push(err.line);
            }
            editor.highlightErrors(errorLines);
        } else if (!result.success) {
            terminal.printSystem(`\n❌ ${result.runtimeError}\n`, 'error');
        } else {
            terminal.printSystem(`\n✅ Готово (${result.executionTimeMs.toFixed(1)} мс)\n`, 'success');
        }
    } catch (err: unknown) {
        if ((err as Error).message !== 'Input cancelled') {
            terminal.printSystem(`\n❌ Ошибка: ${(err as Error).message}\n`, 'error');
        }
    }

    isRunning = false;
    abortController = null;
    updateButtons();
}

// ── Остановка ───────────────────────────────────────────────────────────────

function handleStop(): void {
    if (!isRunning || !terminal) return;

    terminal.cancelInput();
    abortController?.abort();
    isRunning = false;
    abortController = null;
    updateButtons();

    terminal.printSystem('\n⛔ Выполнение прервано.\n', 'info');
}

// ── Сохранение ──────────────────────────────────────────────────────────────

function handleSave(): void {
    if (!editor) return;

    const code = editor.getValue();
    const blob = new Blob([code], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = 'main.idyl';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);

    terminal?.printSystem('💾 Файл сохранён как main.idyl\n', 'success');
}

// ── Загрузка ────────────────────────────────────────────────────────────────

function handleLoad(): void {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.idyl,.txt';

    input.onchange = () => {
        const file = input.files?.[0];
        if (!file || !editor) return;

        const reader = new FileReader();
        reader.onload = () => {
            const content = reader.result as string;
            editor!.setValue(content);
            terminal?.printSystem(`📂 Загружен файл: ${file.name}\n`, 'success');
        };
        reader.onerror = () => {
            terminal?.printSystem(`❌ Не удалось прочитать файл.\n`, 'error');
        };
        reader.readAsText(file);
    };

    input.click();
}

// ── UI ──────────────────────────────────────────────────────────────────────

function updateButtons(): void {
    const runBtn = document.getElementById('btn-run') as HTMLButtonElement | null;
    const stopBtn = document.getElementById('btn-stop') as HTMLButtonElement | null;

    if (runBtn) {
        runBtn.disabled = isRunning;
        runBtn.textContent = isRunning ? '⏳ Выполняется...' : '▶ Запустить';
    }
    if (stopBtn) {
        stopBtn.disabled = !isRunning;
    }
}

// ── Resizer ─────────────────────────────────────────────────────────────────

function initResizer(): void {
    const resizer = document.getElementById('resizer');
    const editorPanel = document.getElementById('editor-panel');
    const terminalPanel = document.getElementById('terminal-panel');

    if (!resizer || !editorPanel || !terminalPanel) return;

    let isResizing = false;

    resizer.addEventListener('mousedown', (e) => {
        isResizing = true;
        document.body.style.cursor = 'col-resize';
        document.body.style.userSelect = 'none';
        e.preventDefault();
    });

    document.addEventListener('mousemove', (e) => {
        if (!isResizing) return;
        const container = editorPanel.parentElement;
        if (!container) return;

        const rect = container.getBoundingClientRect();
        const offset = e.clientX - rect.left;
        const percent = Math.max(20, Math.min(80, (offset / rect.width) * 100));

        editorPanel.style.width = `${percent}%`;
        terminalPanel.style.width = `calc(${100 - percent}% - 5px)`;
    });

    document.addEventListener('mouseup', () => {
        if (isResizing) {
            isResizing = false;
            document.body.style.cursor = '';
            document.body.style.userSelect = '';
        }
    });
}