// =============================================================================
// scope.ts — управление областями видимости
// =============================================================================
//
// Области видимости в Idyllium образуют дерево:
//
//   global
//     ├── function foo
//     │     ├── block (if)
//     │     │     └── block (for) ← loop
//     │     └── block (while) ← loop
//     ├── class Point2D
//     │     ├── method info
//     │     │     └── block
//     │     └── method distance_to
//     │           └── block
//     └── function main
//           └── block
//
// Каждая область видимости хранит свои символы (переменные, параметры)
// и ссылку на родительскую область.  Поиск символа идёт от текущей
// области вверх по цепочке родителей.
//
// Класс Scope — одна область.  Analyzer создаёт и вкладывает их вручную.
// =============================================================================

import { SourceLocation } from './ast';
import { ResolvedType, FunctionParam } from './resolved-types';


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 1 — SYMBOL INFO
// ─────────────────────────────────────────────────────────────────────────────

export type SymbolKind =
    | 'variable'    // локальная переменная
    | 'parameter'   // параметр функции / метода
    | 'function'    // пользовательская функция верхнего уровня
    | 'class'       // объявление класса
    | 'library';    // импортированная библиотека

/**
 * Информация об одном объявленном символе.
 */
export interface SymbolInfo {
    readonly name: string;
    readonly type: ResolvedType;
    readonly kind: SymbolKind;
    readonly loc: SourceLocation;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 2 — CLASS INFO
// ─────────────────────────────────────────────────────────────────────────────

export type AccessModifier = 'public' | 'private';

/** Информация о поле класса. */
export interface FieldInfo {
    readonly name: string;
    readonly type: ResolvedType;
    readonly access: AccessModifier;
}

/** Информация о методе класса. */
export interface MethodInfo {
    readonly name: string;
    readonly returnType: ResolvedType;
    readonly params: FunctionParam[];
    readonly access: AccessModifier;
}

/** Информация о конструкторе. */
export interface ConstructorInfo {
    readonly params: FunctionParam[];
    readonly access: AccessModifier;
}

/**
 * Полная информация об объявленном классе.
 *
 * Хранится в глобальном реестре анализатора.
 * Используется для:
 *   • проверки доступа к полям и методам
 *   • разрешения вызовов конструктора
 *   • проверки наследования
 */
export interface ClassInfo {
    readonly name: string;
    readonly parentName: string | null;
    readonly fields: Map<string, FieldInfo>;
    readonly methods: Map<string, MethodInfo>;
    readonly constructors: ConstructorInfo[];
    readonly hasDestructor: boolean;
    readonly loc: SourceLocation;
}


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 3 — SCOPE TYPE
// ─────────────────────────────────────────────────────────────────────────────

export type ScopeKind =
    | 'global'      // верхний уровень программы
    | 'function'    // тело пользовательской функции
    | 'method'      // тело метода класса
    | 'constructor' // тело конструктора
    | 'block'       // обычный блок (if, else, while, for, etc.)
    | 'loop'        // тело цикла (для валидации break/continue)
    | 'class';      // область класса (для полей и методов)


// ─────────────────────────────────────────────────────────────────────────────
//  SECTION 4 — SCOPE CLASS
// ─────────────────────────────────────────────────────────────────────────────

export class Scope {

    readonly scopeKind: ScopeKind;
    readonly parent: Scope | null;

    /**
     * Тип возвращаемого значения функции/метода, внутри которой
     * находится эта область.  Устанавливается при входе в функцию
     * и наследуется вложенными блоками через getReturnType().
     */
    readonly returnType: ResolvedType | null;

    /**
     * Имя класса, если эта область находится внутри класса.
     * Нужно для валидации использования `this`.
     */
    readonly className: string | null;

    private symbols: Map<string, SymbolInfo> = new Map();

    constructor(
        scopeKind: ScopeKind,
        parent: Scope | null,
        returnType: ResolvedType | null = null,
        className: string | null = null,
    ) {
        this.scopeKind = scopeKind;
        this.parent = parent;
        this.returnType = returnType;
        this.className = className;
    }

    // ── Объявление символов ─────────────────────────────────────────

    /**
     * Объявляет символ в ТЕКУЩЕЙ области.
     * @returns true если объявление успешно, false если имя уже занято.
     */
    declare(info: SymbolInfo): boolean {
        if (this.symbols.has(info.name)) {
            return false;
        }
        this.symbols.set(info.name, info);
        return true;
    }

    // ── Поиск символов ──────────────────────────────────────────────

    /**
     * Ищет символ ТОЛЬКО в текущей области (без подъёма к родителю).
     */
    lookupLocal(name: string): SymbolInfo | null {
        return this.symbols.get(name) ?? null;
    }

    /**
     * Ищет символ в текущей области и всех родительских.
     * Возвращает первый найденный (ближайший по вложенности).
     */
    lookup(name: string): SymbolInfo | null {
        const local = this.symbols.get(name);
        if (local !== undefined) return local;
        if (this.parent !== null) return this.parent.lookup(name);
        return null;
    }

    // ── Контекстные запросы ─────────────────────────────────────────

    /**
     * Находимся ли мы внутри цикла (for/while/do-while)?
     * Нужно для валидации break и continue.
     */
    isInsideLoop(): boolean {
        if (this.scopeKind === 'loop') return true;
        if (this.parent !== null) return this.parent.isInsideLoop();
        return false;
    }

    /**
     * Возвращает ожидаемый тип возвращаемого значения для ближайшей
     * объемлющей функции/метода.  Нужно для валидации return.
     */
    getReturnType(): ResolvedType | null {
        if (this.returnType !== null) return this.returnType;
        if (this.parent !== null) return this.parent.getReturnType();
        return null;
    }

    /**
     * Возвращает имя класса, в контексте которого мы находимся.
     * Нужно для валидации использования `this`.
     */
    getClassName(): string | null {
        if (this.className !== null) return this.className;
        if (this.parent !== null) return this.parent.getClassName();
        return null;
    }

    /**
     * Находимся ли мы внутри функции/метода/конструктора?
     * Нужно для валидации return.
     */
    isInsideFunction(): boolean {
        if (this.scopeKind === 'function' ||
            this.scopeKind === 'method' ||
            this.scopeKind === 'constructor') return true;
        if (this.parent !== null) return this.parent.isInsideFunction();
        return false;
    }
}